{
  "presets": ["next/babel"],
  "plugins": [
    [
      "babel-plugin-styled-components",
      {
        "ssr": true,
        "displayName": true,
        "preprocess": false
      }
    ]
  ]
}

import React, { Component } from "react";
import { Collapse, Slider, DatePicker, Checkbox } from "antd";

import { AsideBusca } from "./styles";
import api from '../../services/api'

const Panel = Collapse.Panel;
const CheckboxGroup = Checkbox.Group;

const initialState = {
  especialidades: [],
}

const options = [];

function onChange(checkedValues) {
  console.log('checked = ', checkedValues);
}

class Aside extends Component {

  state = {
    ...initialState
  }

  componentDidMount(){
    api.get('/especialidades').then(res => {
      this.setState({ especialidades: res.data._embedded.data })
      console.log(res.data._embedded.data)
      for(var i = 0; i < res.data._embedded.data.length; i++) {
        options.push(
          { label: res.data._embedded.data[i].nome, value: res.data._embedded.data[i].nome },
        )
      }
    })
  }

  render() {
    return (
      <AsideBusca>
        <Collapse>
          <Panel header="Especialidade">
            <input type="text" placeholder="Buscar especialidade" />
            <div className="list-specialties">
              <CheckboxGroup options={options} defaultValue={this.props.especialidade} onChange={onChange} />
            </div>
          </Panel>
        </Collapse>
        <Collapse>
          <Panel header="Data disponível">
            <DatePicker />
          </Panel>
        </Collapse>
        <Collapse>
          <Panel header="Preço">
            <Slider range defaultValue={[0, 10000]} min={0} max={10000} />
          </Panel>
        </Collapse>
      </AsideBusca>
    );
  }
}

export default Aside;

import styled from "styled-components";

export const AsideBusca = styled.aside`
  .ant-collapse {
    border: 2px solid #e6e7ef;
    padding: 18px 20px;
    margin-bottom: 15px;
    border-radius: 8px;
    background: transparent;

    .ant-collapse-item {
      border-bottom: 0;

      .ant-collapse-header {
        padding: 0;
        font-family: "Source Sans Pro";
        font-size: 16px;
        color: #202020;
        position: relative;
        padding-right: 30px;
        cursor: pointer;

        .ant-collapse-arrow {
          right: 0px;
          left: auto;
        }
      }
    }

    .ant-collapse-content {
      border-top: 0;
      margin-top: 10px;
    }
  }

  .ant-slider-track {
    background-color: #2c7dfa !important;
  }

  .ant-collapse-content {
    .ant-collapse-content-box {
      padding: 0;
    }
  }

  .ant-slider {
    margin: 14px 11px 10px;
  }

  .ant-slider-handle {
    border: solid 2px #2c7dfa !important;
  }

  .ant-slider-handle {
    width: 18px;
    height: 18px;
    margin-left: -10px;
    margin-top: -7px;
  }

  .ant-calendar-picker {
    width: 100%;

    .ant-input {
      border: 2px solid #e8ecec !important;
    }

    .ant-input {
      padding: 12px 25px;
      height: 43px;
      font-size: 15px;
      color: #a7a7a7;
      font-family: "Source Sans Pro", sans-serif;
    }
  }

  input[type="text"] {
    width: 100%;
    font-weight: 400;
    border: medium none;
    background: none;
    padding: 12px 25px;
    font-size: 15px;
    color: #a7a7a7;
    font-family: "Source Sans Pro", sans-serif;
    margin: 0;
    border: 2px solid #e8ecec;
    border-radius: 8px;
    margin-bottom: 20px;
    height: 43px;
  }

  .list-specialties {
    display: flex;
    flex-direction: column;

    label {
      margin: 0;
      font-family: "Source Sans Pro";
      font-size: 16px;
      color: #888888;
      margin-bottom: 7px;
      display: block;

      .ant-checkbox-checked:after {
        border: 1px solid #2c7dfa;
      }

      .ant-checkbox-inner {
        width: 18px;
        height: 18px;
      }

      .ant-checkbox-checked .ant-checkbox-inner {
        background-color: #2c7dfa;
        border-color: #2c7dfa;
      }

      &:hover {
        .ant-checkbox-inner {
          border-color: #2c7dfa;
        }
      }
    }
  }
`;

import React, { Component, Fragment } from 'react'
import Link from 'next/link'
import { Collapse, Slider, DatePicker, Checkbox, Alert, Popover } from 'antd'
import locale from 'antd/lib/date-picker/locale/pt_BR'
import * as Moment from 'moment'

import Sticky from '../Sticky'
import Footer from '../Footer'
import Horarios from '../Horarios'
import Load from '../Load'

import { connect } from 'react-redux'
import { bindActionCreators } from 'redux'
import api from '../../services/api'

import { Creators as ClinicasActions } from '../../store/ducks/clinicas'

import { Header, Container, CardClinica, AsideBusca } from './styles'

const Panel = Collapse.Panel
const CheckboxGroup = Checkbox.Group

function disabledDate(current) {
	return current && current < Moment().endOf('day')
}

const initialState = {
	clinicas: [],
	clinicasFiltradas: [],
	localizacao: '',
	segmento: '',
	especialidade: [],
	precos: {
		min: 0,
		max: 0,
	},
	precoFiltrado: {
		min: '',
		max: '',
	},
	loading: true,
	dataFilterDiaSemana: '',
	options: [],
	citties: [],
	filters: {
		speciality: [],
		city: [],
	},
}

let rawOptions = []
let rawCitties = []
let rawClinics = []

const styles = {
	h2: { marginTop: '0', flexGrow: '1' },
	bold: { fontWeight: '800' },
}

const formatter = new Intl.NumberFormat('pt-BR', {
	style: 'currency',
	currency: 'BRL',
	minimumFractionDigits: 2,
})

class BuscaComponent extends Component {
	constructor(props) {
		super(props)
		this.filterAll = this.filterAll.bind(this)
	}
	state = {
		...initialState,
		loadingSearch: 'flex',
		alertSearch: 'none',
	}

	componentDidMount() {
		this.setState({
			localizacao: this.props.query.localizacao,
			segmento: this.props.query.idsegmento,
			loading: false,
			dataFilterDiaSemana: this.getDiaSemanaAtual(Moment()),
			dataFilterDiaAno: Moment()
				.add(1, 'd')
				.format('DD/MM/YYYY'),
		})

		this.props.clinicasList()

		const startGet = async () => {
			let clinicas = await this.getClinicas()
			let clinicasProc = []
			// Pegando todos os preços dos serviços
			let precos = []
			await this.asyncForEach(clinicas, async clinica => {
				var cidades = []

				cidades.push(clinica.endereco.cidade)
				rawClinics.push(clinica)

				clinica = await this.getClinicasServicos(clinica)
				await this.asyncForEach(clinica.clinicasServicos, async servico => {
					servico.tabelaServicos.length > 0 && servico.tabelaServicos[0].precoServico
						? precos.push(parseFloat(servico.tabelaServicos[0].precoServico))
						: ''
				})
				clinica = await this.getAgendas(clinica)

				cidades = Array.from(new Set(cidades))

				this.setState({ citties: cidades })
				rawCitties = [...cidades]
				clinicasProc.push(clinica)
			})
			precos.sort((precoA, precoB) => precoA - precoB)

			this.setState(
				{
					clinicas: clinicasProc,
					precos: {
						min: precos[0] == precos[precos.length - 1] ? 0 : precos[0],
						max: precos[precos.length - 1],
					},
					precoFiltrado: {
						min: precos[0] == precos[precos.length - 1] ? 0 : precos[0],
						max: precos[precos.length - 1],
					},
				},
				this.filter
			)
			console.log('Clinicas carregadas!!!')
			if (!clinicasProc.length)
				this.setState({ loadingSearch: 'none', alertSearch: 'block' })
		}

		startGet()

		api.get('/especialidades').then(res => {
			const specialties = []
			for (var i = 0; i < res.data._embedded.data.length; i++) {
				specialties.push({
					label: res.data._embedded.data[i].nome,
					value: res.data._embedded.data[i].nome,
					disabled:
						this.props.query.especialidade &&
						this.props.query.especialidade == res.data._embedded.data[i].nome
							? true
							: false,
				})
			}

			this.setState({
				options: [...specialties],
			})
			rawOptions = [...specialties]

			this.setState({
				especialidades: res.data._embedded.data,
				especialidade:
					this.props.query.especialidade != 'especialidade'
						? [this.props.query.especialidade]
						: [],
			})
		})

		setTimeout(function() {}.bind(this), 3000)
	}

	async asyncForEach(data, callback) {
		for (let index = 0; index < data.length; index++) {
			await callback(data[index], index, data)
		}
	}

	async getClinicas() {
		try {
			let clinicas = await api
				.get(`/clinicas?query[clean]&query[clinicas.ativo]=1`)
				.then(res => {
					return res.data._embedded.data
				})
				.catch(error => {
					console.log(error)
				})
			return clinicas
		} catch (error) {
			console.log('error getClinicas', error)
		}
	}

	async getClinicasServicos(clinica) {
		try {
			let addClinicaServicos = await api
				.get(`/clinicas/${clinica.id}/clinicas-servicos`)
				.then(res1 => {
					clinica.clinicasServicos = res1.data._embedded.data
					return clinica
				})
				.catch(error => {
					console.log(error)
				})
			return addClinicaServicos
		} catch (error) {
			console.log('error getClinicasServicos', error)
		}
	}

	async getAgendas(clinica) {
		try {
			let addAgendas = await api
				.get(`/clinicas/${clinica.id}/agendas`)
				.then(res2 => {
					clinica.agendas = res2.data._embedded.data
					return clinica
				})
				.catch(error => {
					console.log(error)
				})
			return addAgendas
		} catch (error) {
			console.log('error getAgendas', error)
		}
	}

	filter() {
		var clinicasTotal = []
		var clinicasTotalSeg = []
		var clinicasTotalEsp = []
		var clinicaJaListada = []
		const clinicas = this.state.clinicas

		if (this.props.query.localizacao === 'cidade') {
			clinicasTotal = clinicas
		} else {
			for (var i = 0; i < clinicas.length; i++) {
				if (clinicas[i].endereco.cidade === this.state.localizacao) {
					clinicasTotal.push(clinicas[i])
				}
			}
		}

		if (this.props.query.idsegmento !== 'segmento') {
			for (i = 0; i < clinicasTotal.length; i++) {
				for (var x = 0; x < clinicasTotal[i].especialidades.length; x++) {
					clinicaJaListada =
						clinicasTotalSeg === null || clinicasTotalSeg.length <= 0
							? []
							: clinicasTotalSeg.filter(clin => clin.id === clinicasTotal[i].id)
					if (
						clinicasTotal[i].especialidades[x].segmento.id ===
							parseInt(this.props.query.idsegmento) &&
						clinicaJaListada.length == 0
					) {
						clinicasTotalSeg.push(clinicasTotal[i])
					}
				}
			}
		} else {
			clinicasTotalSeg = clinicasTotal
		}

		if (this.props.query.especialidade !== 'especialidade') {
			for (i = 0; i < clinicasTotalSeg.length; i++) {
				for (var x = 0; x < clinicasTotalSeg[i].especialidades.length; x++) {
					if (
						clinicasTotalSeg[i].especialidades[x].nome === this.props.query.especialidade
					) {
						clinicasTotalEsp.push(clinicasTotalSeg[i])
					}
				}
			}
		} else {
			clinicasTotalEsp = clinicasTotalSeg
		}

		this.setState({
			clinicasFiltradas: clinicasTotalEsp,
		})
	}

	numberToReal(numero) {
		const fixedNumero = parseFloat(numero).toFixed(2)
		const num = fixedNumero.split('.')
		num[0] = 'R$ ' + num[0].split(/(?=(?:...)*$)/).join('.')
		return num.join(',')
	}

	viewPreco(tabela) {
		if (tabela.length > 0) {
			const tabelaSite = []
			tabela.forEach(function(item) {
				if (item.tabela && item.tabela.exibirSite) {
					tabelaSite.push(item)
				}
			})

			if (tabelaSite.length > 0 && tabelaSite[0].precoServico) {
				if (tabelaSite[0].tipoPreco === 'Preco fixo') {
					return this.numberToReal(tabelaSite[0].precoServico)
				} else if (tabelaSite[0].tipoPreco === 'A partir') {
					return 'A partir de ' + this.numberToReal(tabelaSite[0].precoServico)
				} else if (tabelaSite[0].tipoPreco === 'Gratuito') {
					return 'Gratuito'
				} else {
					return 'Valor sob consulta'
				}
			} else {
				return 'Valor sob consulta'
			}
		} else {
			return 'Valor sob consulta'
		}
	}

	getDiaSemanaAtual(calendar) {
		let data = calendar ? Moment(calendar).isoWeekday() : ''
		switch (data) {
			case 1:
				data = 'Segunda-feira'
				break
			case 2:
				data = 'Terça-feira'
				break
			case 3:
				data = 'Quarta-feira'
				break
			case 4:
				data = 'Quinta-feira'
				break
			case 5:
				data = 'Sexta-feira'
				break
			case 6:
				data = 'Sábado'
				break
			case 7:
				data = 'Domingo'
				break
			default:
				data = ''
		}
		return data
	}

	searchEspecialidade(e) {
		const { value } = e.target
		const newState = rawOptions.filter(elem => {
			return elem.label.toLowerCase().includes(value.toLowerCase())
		})
		this.setState({ options: newState })
	}

	searchCity(e) {
		const { value } = e.target
		const newState = rawCitties.filter(elem => {
			return elem.toLowerCase().includes(value.toLowerCase())
		})
		this.setState({ citties: newState })
	}

	checkingForCity(rawData, filters) {
		return rawData.filter(clinic => {
			return filters.includes(clinic.endereco.cidade)
		})
	}

	checkingForSpecialty(rawData, filters) {
		const newData = rawData.filter(clinic => {
			let shouldInclude = false

			for (let i = 0; i < clinic.especialidades.length; i++) {
				if (filters.includes(clinic.especialidades[i].nome)) shouldInclude = true
			}
			return shouldInclude
		})

		return newData
	}

	filterAll(value, string) {
		let newState = rawClinics
		let previousSpecialities = this.state.filters.speciality
		let previousCity = this.state.filters.city

		if (string == 'speciality') {
			this.setState({
				filters: {
					...this.state.filters,
					speciality: value,
				},
			})
			previousSpecialities = value
		}

		if (string == 'city') {
			this.setState({
				filters: {
					...this.state.filters,
					city: value,
				},
			})
			previousCity = value
		}

		if (previousCity.length > 0) newState = this.checkingForCity(newState, previousCity)

		if (previousSpecialities.length > 0)
			newState = this.checkingForSpecialty(newState, previousSpecialities)

		console.log(this.state.filters)

		this.setState({ clinicasFiltradas: newState })
	}

	setFiltroData(calendar) {
		this.setState({
			dataFilterDiaSemana: this.getDiaSemanaAtual(calendar),
			dataFilterDiaAno: calendar.format('DD/MM/YYYY'),
		})
	}

	setFiltroPreco(e) {
		let clinicasTotal = []

		if ((e[1] == this.state.precos.max && e[0] == this.state.precos.min) || e[1] == 0) {
			clinicasTotal = this.state.clinicas.slice(0)
		} else {
			this.state.clinicas.forEach(clinicaFor => {
				clinicaFor.clinicasServicos.forEach(servicoFor => {
					if (
						servicoFor.tabelaServicos.length > 0 &&
						servicoFor.tabelaServicos[0].precoServico &&
						servicoFor.tabelaServicos[0].tipoPreco != 'Sob consulta' &&
						servicoFor.tabelaServicos[0].tipoPreco != 'Gratuito' &&
						servicoFor.tabelaServicos[0].tabela &&
						servicoFor.tabelaServicos[0].tabela.exibirSite &&
						parseFloat(servicoFor.tabelaServicos[0].precoServico) >= e[0] &&
						parseFloat(servicoFor.tabelaServicos[0].precoServico) <= e[1] &&
						!clinicasTotal.find(
							clinicaFiltradaItem => clinicaFiltradaItem.id == clinicaFor.id
						)
					) {
						clinicasTotal.push(clinicaFor)
					}
				})
			})
		}

		this.setState({
			clinicasFiltradas: clinicasTotal,
			precoFiltrado: {
				min: e[0],
				max: e[1],
			},
		})
	}

	slugify = text => {
		return text
			.toString()
			.toLowerCase()
			.replace(/\s+/g, '-')
			.replace(/[^\w\-]+/g, '')
			.replace(/\-\-+/g, '-')
			.replace(/^-+/, '')
			.replace(/-+$/, '')
	}

	returnSpecialityPopover() {
		const content = (
			<div>
				{this.state.filters.speciality.map((elem, index) => {
					if (index != 0) return <p>{elem}</p>
				})}
			</div>
		)
		const specialityDisplayed =
			this.state.filters.speciality.length > 0
				? this.state.filters.speciality[0]
				: 'Todas especialidades'
		const numberSpecialities =
			this.state.filters.speciality.length <= 1
				? ''
				: `+${this.state.filters.speciality.length - 1} `
		const popover = (
			<span>
				{specialityDisplayed}{' '}
				<Popover placement="bottom" content={content}>
					{numberSpecialities}
				</Popover>
			</span>
		)
		return popover
	}

	returnCityPopover() {
		const content = (
			<div>
				{this.state.filters.city.map((elem, index) => {
					if (index != 0) return <p>{elem}</p>
				})}
			</div>
		)
		const cityDisplayed =
			this.state.filters.city.length > 0 ? this.state.filters.city[0] : 'Todas cidades'
		const numberCitties =
			this.state.filters.city.length <= 1 ? '' : `+${this.state.filters.city.length - 1}`
		const popover = (
			<span>
				{cityDisplayed}{' '}
				<Popover placement="bottom" content={content}>
					{numberCitties}
				</Popover>
			</span>
		)
		return popover
	}

	returnValorMinAndMax() {
		if (
			this.state.precoFiltrado.max == this.state.precoFiltrado.min &&
			this.state.precoFiltrado.max != 0
		) {
			return `com o valor de ${this.state.precoFiltrado.max} reais`
		} else if (this.state.precoFiltrado.max > 0 && this.state.precoFiltrado.min > 0) {
			return `entre ${this.state.precoFiltrado.min} e ${
				this.state.precoFiltrado.max
			} reais`
		} else if (this.state.precoFiltrado.max > 0 && this.state.precoFiltrado.min == 0) {
			return `até ${this.state.precoFiltrado.max} reais`
		} else {
			return 'com qualquer valor'
		}
	}

	render() {
		const { clinicas, clinicasFiltradas, loadingSearch, alertSearch } = this.state
		var segmentos = []

		return (
			<Fragment>
				<Sticky inside={true} />
				<Header>
					<h1>Resultado das buscas</h1>
				</Header>
				<Container>
					<div className="container">
						{/* <Aside especialidade={this.props.query.especialidade} /> */}
						<AsideBusca>
							<Collapse>
								<Panel header="Cidade">
									<input
										type="text"
										placeholder="Buscar cidade"
										onChange={e => this.searchCity(e)}
									/>
									<div className="list-specialties">
										<CheckboxGroup
											options={this.state.citties}
											onChange={e => this.filterAll(e, 'city')}
										/>
									</div>
								</Panel>
							</Collapse>
							<Collapse>
								<Panel header="Especialidade">
									<input
										type="text"
										placeholder="Buscar especialidade"
										onChange={e => this.searchEspecialidade(e)}
									/>
									<div className="list-specialties">
										<CheckboxGroup
											options={this.state.options}
											defaultValue={this.state.especialidade}
											onChange={e => this.filterAll(e, 'speciality')}
										/>
									</div>
								</Panel>
							</Collapse>
							<Collapse>
								<Panel header="Data disponível">
									<DatePicker
										locale={locale}
										disabledDate={disabledDate}
										format={'DD/MM/YYYY'}
										defaultValue={Moment().add(1, 'd')}
										onChange={e => this.setFiltroData(e)}
										style={{ width: '100%' }}
									/>
								</Panel>
							</Collapse>
							<Collapse>
								<Panel header="Preço">
									<Slider
										range
										step={50}
										tipFormatter={formatter.format}
										defaultValue={[this.state.precos.min, this.state.precos.max]}
										min={this.state.precos.min}
										max={this.state.precos.max}
										onAfterChange={e => this.setFiltroPreco(e)}
									/>
								</Panel>
							</Collapse>
						</AsideBusca>
						<div className="result">
							<h2 style={styles.h2}>
								Resultados para{' '}
								<span style={styles.bold}>{this.returnSpecialityPopover()}</span>
								próximos a <span style={styles.bold}>
									{this.returnCityPopover()}
								</span>{' '}
								<span style={styles.bold}>
									{this.state.dataFilterDiaAno
										? `no dia ${this.state.dataFilterDiaAno} `
										: ' '}
								</span>
								<span style={styles.bold}>{this.returnValorMinAndMax()}</span>
							</h2>

							{this.state.loading && <Load />}
							{clinicas &&
								!this.state.loading &&
								clinicasFiltradas.map(clinica => (
									<CardClinica key={clinica.id}>
										<div className="head">
											<Link
												href={`/detalhes/${this.slugify(clinica.nomeFantasia)}/${
													clinica.id
												}/informacoes`}
											>
												<a className="logo">
													{clinica.logotipo.tmp_name && (
														<img
															src={clinica.logotipo.tmp_name.replace(
																's3://',
																'//s3.amazonaws.com/'
															)}
															alt={`Logotipo ${clinica.nomeFantasia}`}
														/>
													)}
												</a>
											</Link>
											<div className="description">
												<h3>
													<Link
														href={`/detalhes/${this.slugify(clinica.nomeFantasia)}/${
															clinica.id
														}/informacoes`}
													>
														<a>{clinica.nomeFantasia}</a>
													</Link>
												</h3>
												<address>
													<i className="fas fa-map-marker-alt" /> Av. Dr.
													{clinica.endereco.logradouro}, nº {clinica.endereco.numero},{' '}
													{clinica.endereco.bairro} - {clinica.endereco.cidade} -{' '}
													{clinica.endereco.uf}
												</address>
												{clinica.especialidades.length > 0 && (
													<p className="specialties">
														<i className="fas fa-briefcase-medical" />{' '}
														{clinica.especialidades.map((especialidade, index) =>
															clinica.especialidades.length === index + 1
																? especialidade.nome
																: `${especialidade.nome}, `
														)}
													</p>
												)}
												{clinica.especialidades.length > 0 && (
													<h4 id={`segmentos-clinica-${clinica.id}`}>
														{clinica.especialidades.map((especialidade, index) => {
															segmentos[clinica.id] =
																index == 0 ? '' : segmentos[clinica.id]

															if (
																segmentos[clinica.id].indexOf(
																	especialidade.segmento.nome
																) < 0
															) {
																segmentos[clinica.id] += `${
																	especialidade.segmento.nome
																}, `
																return index === 0
																	? especialidade.segmento.nome
																	: `, ${especialidade.segmento.nome}`
															}
														})}
													</h4>
												)}
											</div>
										</div>

										{clinica.clinicasServicos && clinica.clinicasServicos.length > 0 && (
											<Collapse className="body" bordered={false} defaultActiveKey={['']}>
												<Panel
													key={clinica.id}
													header={
														<span
															style={{
																color: 'rgba(0,0,0,.85)',
																fontSize: '19px',
																fontWeight: '600',
																fontFamily: "'Source Sans pro', sans-serif",
															}}
														>
															Serviços
														</span>
													}
												>
													<Collapse>
														{clinica.clinicasServicos.map(
															(servico, index) =>
																servico.tabelaServicos.length &&
																servico.tabelaServicos[0].tabela &&
																servico.tabelaServicos[0].tabela.ativo &&
																servico.profissionalServico &&
																servico.profissionalServico.length > 0 && (
																	<Panel
																		key={index}
																		header={
																			<div className="service-container">
																				<p className="service-title">
																					{servico.servico.titulo}
																				</p>
																				<p className="service-price">
																					{this.viewPreco(servico.tabelaServicos)}
																				</p>
																			</div>
																		}
																	>
																		<div className="timesheet">
																			{servico.profissionalServico.map(
																				(item, index) =>
																					item.profissional &&
																					item.profissional.horarios &&
																					item.profissional.horarios.length > 0 && (
																						<Horarios
																							key={index}
																							dataHorario={this.state.dataFilterDiaSemana}
																							horario={this.state.dataFilterDiaAno}
																							profissional={item.profissional}
																							clinica={clinica.nomeFantasia}
																							agenda={clinica.agendas}
																							servico={servico.servico.titulo}
																							agendamentoExterno={
																								servico.agendamentoExterno
																							}
																							idProfissional={item.profissional.id}
																							idServico={servico.id}
																							idClinica={clinica.id}
																						/>
																					)
																			)}
																		</div>
																	</Panel>
																)
														)}
													</Collapse>
												</Panel>
											</Collapse>
										)}
									</CardClinica>
								))}
							{clinicasFiltradas.length == 0 && !this.state.loading && (
								<div className="found" style={{ width: '100%' }}>
									<div className="lds-ring" style={{ display: loadingSearch }}>
										<div />
										<div />
										<div />
										<div />
									</div>
									<Alert
										style={{ display: alertSearch }}
										message="Não foi encontrado nenhuma cliníca de acordo com os valores filtrados!"
										type="error"
									/>
								</div>
							)}
							{/* <Pagination defaultCurrent={6} total={500} /> */}
						</div>
					</div>
				</Container>
				<Footer />
			</Fragment>
		)
	}
}

const mapStateToProps = state => ({
	clinicas: state.clinicas.data._embedded && state.clinicas.data._embedded.data,
	loading: state.clinicas.loading,
})

const mapDispatchToProps = dispatch =>
	bindActionCreators(
		{
			...ClinicasActions,
		},
		dispatch
	)

export default connect(
	mapStateToProps,
	mapDispatchToProps
)(BuscaComponent)

