import React, { Fragment } from "react";
import Link from 'next/link'
import { Form, Input, Icon, Button, notification, Select, Divider, InputNumber, Checkbox } from 'antd';
import MaskedInput from 'react-text-mask'
import ViaCep from 'react-via-cep'
import Sticky from "../Sticky";
import Footer from "../Footer";
import { Container, ButtonModal } from "./styles";
import api from "../../services/api";
import ConsentContent from '../ConsentComponent/ConsentContent'
import TermsContent from '../TermsComponent/TermsContent'
import PrivacyContent from '../PrivacyComponent/PrivacyContent'

import { Header } from "../BuscaComponent/styles";
import { LoadContainer } from "../Load/styles";
import Load from "../Load";
import { Modal} from 'antd'
import { relativeTimeThreshold } from "moment";

const FormItem = Form.Item
const Option = Select.Option
const { TextArea } = Input

let id = 0

const initialState = {
    confirmDirty: false,
    clinics: [],
    data: [
        {
            nome: '',
            email: '',
            dataNascimento: '',
            termosAceitos: false,
            endereco: {
                cep: null,
                uf: '',
                cidade: '',
                bairro: '',
                logradouro: '',
                numero: null,
                complemento: '',
            },
            telefones: [
                {
                    numero: '',
                    preferencial: true,
                },
            ],
            genero: '',
            estadoCivil: '',
            cpf: '',
            convenios: '',
            nomeDependentes: '',
            user: {
                password: '',
                username: '',
                verifyPassword: '',
            },
            origem: 'web'
        },
    ],

}

class CadastroComponent extends React.Component {

    constructor(props) {
        super(props)
        this.state = {
            cep: '',
            cepCidade: '',
            cepEstado: '',
            current: 0,
            confirmDirty: true,
            loading: false,
            displayAddress: false,
            displayPersonalData: false,
            modalTermosDeConsentimento: false,
            modalTermosDeUso: false,
            modalPoliticaPrivacidade: false,
            modalConfirmaTermos: false,
            termsChecked: false,
            confirmaTermos: false,
            ...initialState,
        }

        this.handleChangeCep = this.handleChangeCep.bind(this);
        this.handleSuccess = this.handleSuccess.bind(this);
        this.handleAddAddress = this.handleAddAddress.bind(this);
        this.handleAddPersonalData = this.handleAddPersonalData.bind(this);
        this.modalTermosDeConsentimento = this.modalTermosDeConsentimento.bind(this);
        this.modalTermosDeUso = this.modalTermosDeUso.bind(this);
        this.modalPoliticaPrivacidade = this.modalPoliticaPrivacidade.bind(this);
        this.modalConfirmaTermos = this.modalConfirmaTermos.bind(this);
        this.getFormFields = this.getFormFields.bind(this)
        this.handleTermsCheck = this.handleTermsCheck.bind(this);
    }

    handleChangeCep(evt) {
        this.setState({ cep: evt.target.value })
    }

    handleSuccess(cepData) {
        this.props.form.setFieldsValue({
            uf: cepData.uf,
            cidade: cepData.localidade,
            cep: cepData.cep,
            logradouro: cepData.logradouro,
            bairro: cepData.bairro,
            complemento: cepData.complemento,
        })
    }

    next() {
        const current = this.state.current + 1
        this.setState({ current })
    }

    prev() {
        const current = this.state.current - 1
        this.setState({ current })
    }

    handleConfirmBlur = e => {
        const value = e.target.value
        this.setState({ confirmDirty: this.state.confirmDirty || !!value })
    }

    handleAddAddress() {

        this.setState({ displayAddress: !this.state.displayAddress });
    }

    handleAddPersonalData() {

        this.setState({ displayPersonalData: !this.state.displayPersonalData });
    }

    async save() {
        const dados = this.state.data[0]
        await api.post('/clientes', dados)
            .then(res => {
                notification.success({
                    message: 'Cadastrado com sucesso!',
                })

                setTimeout(
                    function () {
                        window.location.href = "/login";
                    }
                        .bind(this),
                    2500
                );
            })
            .catch(error => {
                this.setState({ loading: false })
                this.returnMsg(error.response)
            })
    }


    remove = k => {
        const { form } = this.props
        // can use data-binding to get
        const keys = form.getFieldValue('keys')
        // We need at least one passenger
        if (keys.length === 1) {
            return
        }

        // can use data-binding to set
        form.setFieldsValue({
            keys: keys.filter(key => key !== k),
        })
    }

    add = () => {
        const { form } = this.props
        // can use data-binding to get
        const keys = form.getFieldValue('keys')
        const nextKeys = keys.concat(++id)
        // can use data-binding to set
        // important! notify form to detect changes
        form.setFieldsValue({
            keys: nextKeys,
        })
    }

    returnMsg(responseData) {
        if (responseData !== undefined) {
            const msgs = []
            const arrResults = []
            const erros = responseData.data.validation_messages || {};
            const arrFields = Object.keys(erros)

            if (responseData.status !== 200 && responseData.status !== 201) {
                const results = Object.values(erros)
                // console.log(results)

                for (var i = 0; i < results.length; i++) {
                    arrResults.push([results[i]])
                }

                // console.log(arrResults)
                for (i = 0; i < arrFields.length; i++) {
                    if (typeof arrResults[i] === 'string' || arrResults[i] instanceof String) {
                        var objresult = arrResults[i]
                    } else {
                        const msgresult = Object.values(arrResults[i][0])
                        // console.log(msgresult[0])
                        if (typeof msgresult[0] === 'string' || msgresult[0] instanceof String) {
                            objresult = msgresult[0]
                        } else {
                            objresult = Object.values(msgresult[0])
                        }
                    }

                    // console.log(objresult)
                    if (typeof objresult === 'string' || objresult instanceof String) {
                        var retorno = objresult
                    } else if (typeof objresult[0] === 'string' || objresult[0] instanceof String) {
                        retorno = objresult[0]
                    } else {
                        const objresult2 = Object.values(objresult[0])
                        retorno = ''
                        for (i = 0; i < objresult2.length; i++) {
                            retorno += objresult2[i] + ' | '
                        }
                    }
                    msgs.push([
                        {
                            status: responseData.status,
                            field: 'Erro ao cadastrar!',
                            message: retorno,
                            type: 'error',
                        },
                    ])
                }
            }

            for (i = 0; i < msgs.length; i++) {
                const msgfinal = Object.entries(msgs[i])
                // console.log(msgfinal)
                notification.error({
                    message: msgfinal[0][1].field,
                    description: msgfinal[0][1].message,
                })
            }
        }
    }

    handleSubmit = e => {
        e.preventDefault()
        if(this.state.confirmaTermos == false){

           return  this.setState({modalConfirmaTermos: true})
        }
        this.getFormFields()
    }

   getFormFields(){
    this.props.form.validateFields((err, values) => {

        if (!err) {
            this.setState({ loading: true })

            const data = { ...this.state.data }

            if (values['dataNascimento']) {
                var nascimento = values['dataNascimento']
                var dataSplit = nascimento.split('/')
                var dataFinalMesmo = dataSplit[2] + '-' + dataSplit[1] + '-' + dataSplit[0]
            } else {
                dataFinalMesmo = null
            }

            var phones = []

            for (var i = 0; i < values.telefones.length; i++) {
                if (values.telefones[i] !== undefined) {
                    phones.push({
                        numero: values.telefones[i],
                        preferencial: i === 0 ? true : false,
                    })
                }
            }

            data[0].telefones = phones
            data[0].endereco.cep = values['cep']
            data[0].endereco.uf = values['uf']
            data[0].endereco.cidade = values['cidade']
            data[0].endereco.logradouro = values['logradouro']
            data[0].endereco.bairro = values['bairro']
            data[0].endereco.numero = values['numero']
            data[0].endereco.complemento = values['complemento']
            data[0].genero = values['genero']
            data[0].dataNascimento = dataFinalMesmo
            data[0].nomeDependentes = values['dependentes']
            data[0].origem = this.state.origem
            data[0].user.username = values['email']
            data[0].user.password = values['password']
            data[0].user.verifyPassword = values['confirm']
            data[0].user.roles = 8
            data[0].termosAceitos = values['checkedTermos']
            if (data[0].endereco.cep == undefined) data[0].endereco = null;
            if (data[0].genero == undefined) data[0].genero = null;
            if (data[0].nomeDependentes == undefined) data[0].nomeDependentes = null;
            if (data[0].origem == undefined) data[0].origem = null;


            this.setState({ data })



            this.save()
        }
    })
   }

    onChangeDate(value, dateString) {
        console.log('Selected Time: ', value)
        console.log('Formatted Selected Time: ', dateString)
    }

    updateFild(event) {
        const data = { ...this.state.data }
        if (event.target.name === 'cep') {
            data[0]['endereco']['cep'] = parseInt(event.target.value, 10)
        } else if (event.target.name === 'cidade') {
            data[0]['endereco']['cidade'] = event.target.value
        } else if (event.target.name === 'complemento') {
            data[0]['endereco']['complemento'] = event.target.value
        } else if (event.target.name === 'logradouro') {
            data[0]['endereco']['logradouro'] = event.target.value
        } else if (event.target.name === 'numero') {
            data[0]['endereco']['numero'] = event.target.value
        } else if (event.target.name === 'bairro') {
            data[0]['endereco']['bairro'] = event.target.value
        } else {
            data[0][event.target.name] = event.target.value
        }
        this.setState({ data })
        // console.log(this.state.data)
    }

    compareToFirstPassword = (rule, value, callback) => {
        const form = this.props.form
        if (value && value !== form.getFieldValue('password')) {
            callback('As senhas não são iguais!')
        } else {
            callback()
        }
    }

    validateToNextPassword = (rule, value, callback) => {
        const form = this.props.form
        if (value && this.state.confirmDirty) {
            form.validateFields(['confirm'], { force: true })
        }
        callback()
    }

    state = {
        loading: true,
    };

    handleTermsCheck() {
        if(!this.state.termsChecked) {
            this.setState({ confirmaTermos:true})
        } else {
            this.setState({ confirmaTermos:false})
        }
    }

