                                        {getFieldDecorator('checkedTermos',{
                                            initialValue:this.state.termsChecked,
                                            valuePropName:'checked'
                                        })(
                                                <Checkbox onChange={this.handleTermsCheck}/>
                                            )}
                                        <span>Li e concordo com os <a onClick={() => this.setState({ modalTermosDeUso: true})}>Termos de Uso</a>, <a onClick={() => this.setState({ modalPoliticaPrivacidade: true})}>Política de Privacidade</a> e <a onClick={() => this.setState({ modalTermosDeConsentimento: true})}>Termo de Consentimento.</a></span>
                                        </FormItem>
                                    </div>
                                    <div className="col-lg-12" style={{ textAlign: 'right' }}>
                                        <Link href="/login">
                                            <Button>Voltar</Button>
                                        </Link>
                                        <Button
                                            style={{ marginLeft: '10px' }}
                                            htmlType="submit"
                                            className="btn-green"

                                        >
                                            Cadastrar
                                        </Button>
                                    </div>
                                </div>

                            </Form>
                        </Container>
                    </Fragment>
                )}
                <Footer />
            </Fragment>
        )
    }
}

const CadastroComponentForm = Form.create()(CadastroComponent)
export default CadastroComponentForm

