import { Creators as ClinicasActions } from '../../store/ducks/clinicas'
import { Creators as ProfissionaisActions } from '../../store/ducks/profissionais'
import { connect } from 'react-redux'
import { bindActionCreators } from 'redux'
import moment from 'moment'

const Option = Select.Option

function disabledDate(current) {
	return current && current < moment().endOf('day')
}

const profissionalObject = function(
	id = '',
	nome = '',
	nomeConselho = '',
	numeroRegistro = '',
	foto = null,
	horarios = [],
	servicos = [],
	profissionalIntervalos = []
) {
	this.id = id
	this.nome = nome
	this.nomeConselho = nomeConselho
	this.numeroRegistro = numeroRegistro
	this.foto = foto
	this.horarios = horarios
	this.servicos = servicos
	this.profissionalIntervalos = profissionalIntervalos
}

let servicoArray = []

class DetalhesComponent extends Component {
	state = {
		loading: true,
		agendaProfissionaisList: [],
		profissionais: [],
		profissional: { nome: '', horarios: [], servicos: [], profissionalIntervalos: [] },
		servicos: [],
		servicosFiltrados: [],
		categorias: [],
		atualCategoriaFiltrada: '',
		formFiltroServicos: {
			servico: '',
			data: '',
		},
		visible: false,
		dataFilterDiaSemana: '',
		modalTitle: '',
		modalHorarios: '',
		loadingSearch: 'block',
		alertSearch: 'none',
		clinicasServicos: [],
		agendasClinica: [],
	}

	showModal = () => {
		this.setState({
			visible: true,
		})
	}

	hideModal = () => {
		this.setState({
			visible: false,
		})
	}

	async getClinicas() {
		try {
			let clinicas = await api
				.get(`/clinicas/${this.props.query.id}/agendas`)
				.then(res2 => {
					return res2.data._embedded.data
				})
				.catch(error => {
					console.log(error)
				})
			return clinicas
		} catch (error) {
			console.log('error getClinicas', error)
		}
	}

	componentDidMount() {
		this.props.clinicaDetails(this.props.query.id)

		const startGet = async () => {
			let clinicas = await this.getClinicas()
			this.setState((this.agendasClinica = clinicas))
			this.setState({ loadingSearch: 'none', alertSearch: 'block' })
			this.setState({ loading: false })
		}

		startGet()
	}

	componentDidUpdate(prevProps, prevState) {
		if (this.props.clinica !== prevProps.clinica) {
			this.getClinicasServicos(this.props.clinica.id)
		}
	}

	filtroOnChange() {
		this.setState({
			agendaProfissionaisList: this.getAgendaProfissionais(
				this.state.formFiltroServicos.servico,
				this.state.formFiltroServicos.data
			),
		})
	}

	setFiltroData(calendar) {
		let data = calendar ? Moment(calendar).isoWeekday() : ''
		switch (data) {
			case 1:
				data = 'Segunda-feira'
				break
			case 2:
				data = 'Terça-feira'
				break
			case 3:
				data = 'Quarta-feira'
				break
			case 4:
				data = 'Quinta-feira'
				break
			case 5:
				data = 'Sexta-feira'
				break
			case 6:
				data = 'Sábado'
				break
			case 7:
				data = 'Domingo'
				break
			default:
				data = ''
		}
		this.setState(
			{
				formFiltroServicos: {
					...this.state.formFiltroServicos,
					data: data,
					dateSelect: Moment(calendar).format('DD/MM/YYYY'),
				},
			},
			this.filtroOnChange
		)
	}

	setFiltroServico(e) {
		this.setState(
			{ formFiltroServicos: { ...this.state.formFiltroServicos, servico: e } },
			this.filtroOnChange
		)
	}

	getClinicasServicos(clinicaId) {
		const { aba } = this.props.query
		api
			.get(
				`/clinicas/${clinicaId}/clinicas-servicos${
					aba === 'servicos' ? '' : '?query[clinicasServicos.agendamentoExterno]=1'
				}`
			)
			.then(res1 => {
				this.setState({ clinicasServicos: res1.data._embedded.data })

				this.props.clinica.clinicasServicos = res1.data._embedded.data
				this.setState({
					clinicasServicos: res1.data._embedded.data,
					profissionais: this.getProfissionais(),
					servicos: this.getServicos(),
					servicosFiltrados: this.getServicos(),
					categorias: this.getCategorias(),
				})
			})
	}

	getAgendaProfissionais(servicoHorario, data) {
		let profissionais = []
		if (this.props.clinica.clinicasServicos && servicoHorario && data) {
			this.props.clinica.clinicasServicos.forEach(clinicaServico => {
				if (clinicaServico.id == servicoHorario) {
					clinicaServico.profissionalServico.forEach(profissionalServico => {
						if (
							profissionalServico.profissional.horarios.find(
								profissionalHorario =>
									profissionalHorario && profissionalHorario.nome == data
							)
						) {
							var servico = {}
							servico.id = clinicaServico.id
							servico.titulo = clinicaServico.servico.titulo
							servico.agendamentoExterno = clinicaServico.agendamentoExterno

							profissionais.push(
								new profissionalObject(
									profissionalServico.profissional.id,
									profissionalServico.profissional.nome,
									profissionalServico.profissional.nomeConselho,
									profissionalServico.profissional.numeroRegistro,
									profissionalServico.profissional.foto,
									profissionalServico.profissional.horarios,
									servico,
									profissionalServico.profissional.profissionalIntervalos
								)
							)
						}
					})
				}
			})
		}
		return profissionais
	}

	getProfissionais() {
		let profissionais = []

		if (this.props.clinica.clinicasServicos) {
			this.props.clinica.clinicasServicos.forEach(clinicaServico => {
				clinicaServico.profissionalServico.forEach(profissionalServico => {
					if (
						profissionais.findIndex(
							index => index.id == profissionalServico.profissional.id
						) == -1
					) {
						profissionais.push(
							new profissionalObject(
								profissionalServico.profissional.id,
								profissionalServico.profissional.nome,
								profissionalServico.profissional.nomeConselho,
								profissionalServico.profissional.numeroRegistro,
								profissionalServico.profissional.foto
							)
						)
					}
				})
			})
			this.props.clinica.clinicasServicos.forEach(clinicaServico => {
				clinicaServico.profissionalServico.forEach(profissionalServico => {
					let profissionalIndex = profissionais.findIndex(
						index => index.id == profissionalServico.profissional.id
					)
					if (profissionalIndex > -1) {
						var objServ = {}
						objServ.id = clinicaServico.id
						objServ.titulo = clinicaServico.servico.titulo
						objServ.agendamentoExterno = clinicaServico.agendamentoExterno
						profissionais[profissionalIndex].servicos.push(objServ)
					}
				})
			})
			this.props.clinica.clinicasServicos.forEach(clinicaServico => {
				clinicaServico.profissionalServico.forEach(profissionalServico => {
					let profissionalIndex = profissionais.findIndex(
						index => index.id == profissionalServico.profissional.id
					)
					if (profissionalIndex > -1) {
						profissionais[profissionalIndex].horarios.push(
							profissionalServico.profissional.horarios
						)
					}
				})
			})
			this.props.clinica.clinicasServicos.forEach(clinicaServico => {
				clinicaServico.profissionalServico.forEach(profissionalServico => {
					let profissionalIndex = profissionais.findIndex(
						index => index.id == profissionalServico.profissional.id
					)
					if (profissionalIndex > -1) {
						profissionais[profissionalIndex].profissionalIntervalos.push(
							profissionalServico.profissional.profissionalIntervalos
						)
					}
				})
			})
			return profissionais
		} else {
			return []
		}
	}

	getServicos() {
		let servicos = []
		if (this.state.clinicasServicos) {
			this.state.clinicasServicos.forEach(item => {
				if (
					item &&
					item.tabelaServicos &&
					item.tabelaServicos.length &&
					item.tabelaServicos[0].tabela &&
					item.tabelaServicos[0].tabela.ativo &&
					item.tabelaServicos[0].tabela.exibirSite
				) {
					servicos.push({
						id: item.servico.id,
						nome: item.servico.titulo,
						descricao: item.descricao,
						tempoMedioDuracao: item.tempoMedioDuracao,
						tabelaServicos: item.tabelaServicos,
						categoria: {
							id: item.categoria !== null ? item.categoria.id : item.servico.categoria.id,
							nome:
								item.categoria !== null
									? item.categoria.nome
									: item.servico.categoria.nome,
						},
					})
				}
			})

			return servicos.sort(
				(a, b) => a.tabelaServicos[0].precoServico - b.tabelaServicos[0].precoServico
			)
		} else {
			return []
		}
	}

	getCategorias() {
		let categorias = []
		if (this.props.clinica.clinicasServicos) {
			this.props.clinica.clinicasServicos.forEach(item => {
				if (
					item.tabelaServicos.length &&
					item.tabelaServicos[0].tabela &&
					item.tabelaServicos[0].tabela.exibirSite
				) {
					if (
						categorias.findIndex(index => index.id == item.servico.categoria.id) == -1
					) {
						categorias.push({
							id: item.categoria !== null ? item.categoria.id : item.servico.categoria.id,
							nome:
								item.categoria !== null
									? item.categoria.nome
									: item.servico.categoria.nome,
						})
					}
				}
			})
			return categorias
		} else {
			return []
		}
	}

	categoriaFilter(categoriaId) {
		if (categoriaId) {
			this.setState({
				servicosFiltrados: this.state.servicos.filter(
					servico => servico.categoria.id == categoriaId
				),
			})
		} else {
			this.setState({ servicosFiltrados: this.state.servicos })
		}
		this.setState({ atualCategoriaFiltrada: categoriaId })
	}

	todayWeekday() {
		const d = new Date()
		const weekday = []
		weekday[0] = 'Domingo'
		weekday[1] = 'Segunda-feira'
		weekday[2] = 'Terça-feira'
		weekday[3] = 'Quarta-feira'
		weekday[4] = 'Quinta-feira'
		weekday[5] = 'Sexta-feira'
		weekday[6] = 'Sábado'

		return weekday[d.getDay()]
	}

	numberToReal(numero) {
		const fixedNumero = parseFloat(numero).toFixed(2)
		const num = fixedNumero.split('.')
		num[0] = 'R$ ' + num[0].split(/(?=(?:...)*$)/).join('.')
		return num.join(',')
	}

	viewPreco(tabela) {
		if (tabela.length > 0) {
			const tabelaSite = []
			tabela.forEach(function(item) {
				if (item.tabela && item.tabela.exibirSite) {
					tabelaSite.push(item)
				}
			})

			if (tabelaSite.length > 0 && tabelaSite[0].precoServico) {
				if (tabelaSite[0].tipoPreco === 'Preco fixo') {
					return this.numberToReal(tabelaSite[0].precoServico)
				} else if (tabelaSite[0].tipoPreco === 'A partir') {
					return 'A partir de ' + this.numberToReal(tabelaSite[0].precoServico)
				} else if (tabelaSite[0].tipoPreco === 'Gratuito') {
					return 'Gratuito'
				} else {
					return 'Valor sob consulta'
				}
			} else {
				return 'Valor sob consulta'
			}
		} else {
			return 'Valor sob consulta'
		}
	}

	updateProfissionalModal(profissional) {
		const prof = { ...profissional }
		this.setState(
			{
				profissional: prof,
			},
			() => {
				this.showModal()
			}
		)
	}

	getServicoImagemPath(servico) {
		switch (servico) {
			case 1:
				return 'Segunda-feira'
			default:
				return '/static/logo_icon.png'
		}
	}

	exibirFotoProfissional(profissional) {
		if (profissional && profissional.foto) {
			return (
				<img
					src={profissional.foto.tmp_name.replace('s3://', '//s3.amazonaws.com/')}
					alt={profissional.nome}
				/>
			)
		} else {
			return <img src="/static/user.svg" alt="" />
		}
	}

