										}}
									>
										<h2>Lista de profissionais</h2>
										{this.state.agendaProfissionaisList.length > 0
											? this.state.agendaProfissionaisList.map((profissional, index) => (
													<Horarios
														key={index}
														dataHorario={this.state.formFiltroServicos.data}
														profissional={profissional}
														servico={
															this.state.agendaProfissionaisList[0].servicos.titulo
														}
														horario={this.state.formFiltroServicos.dateSelect}
														clinica={this.props.clinica.nomeFantasia}
														agenda={this.agendasClinica}
														agendamentoExterno={
															this.state.agendaProfissionaisList[0].servicos
																.agendamentoExterno
														}
														idProfissional={profissional.id}
														idServico={this.state.formFiltroServicos.servico}
														idClinica={this.props.clinica.id}
													/>
											  ))
											: ''}
									</div>
								</div>
							)}
						</Container>
					</Fragment>
				)}

				<Footer />
			</Fragment>
		)
	}
}

const mapStateToProps = state => ({
	clinica: state.clinicas.data,
	profissionais: state.profissionais.data,
	loading: state.clinicas.loading,
})

const mapDispatchToProps = dispatch =>
	bindActionCreators(
		{
			...ClinicasActions,
			...ProfissionaisActions,
		},
		dispatch
	)

export default connect(
	mapStateToProps,
	mapDispatchToProps
)(DetalhesComponent)

