import React, { Fragment } from "react";
import { Form, Input, Button, notification } from 'antd';
import Sticky from "../Sticky";
import Footer from "../Footer";
import { Hero } from "./styles";
import api from "../../services/api";
import { Link, Router } from "../../routes";

const FormItem = Form.Item

class ForgotPasswordComponent extends React.Component {

  handleSubmit = e => {
    e.preventDefault();
    this.props.form.validateFields(async (err, values) => {
      if (!err) {
        const { username } = values;
        const domain = location.origin
					try {
						await api.post('/recuperar-senha', {
							username,
              domain,
						})
						notification.success({
							message: 'Um link de recuperação foi enviado ao seu email.',
						})
						Router.pushRoute('/login');
					} catch (error) {
						let errorMsg = 'Ocorreu um erro, por favor tente novamente.'
						if (error.response && error.response.status === 400) {
							errorMsg = error.response.data.detail
						}
						notification.error({
							message: errorMsg,
						})
					}
      }
    });
  };

  handleSubmitNewPassword = event => {
		event.preventDefault()

		const { form, token } = this.props;

    form.validateFields(async (error, values) => {
      if (!error) {
        try {
          const { senha, confSenha } = values
          await api.patch(`/recuperar-senha/${token}`, {
            password: senha,
            verifyPassword: confSenha,
          })
          notification.success({
            message: 'Senha redefinida com sucesso. Faça login com a nova senha.',
          })
          Router.pushRoute('/login');
        } catch (error) {
          let errorMsg = 'Ocorreu um erro, por favor tente novamente.'
          if (error.response && error.response.status === 400) {
            errorMsg = error.response.data.detail
          }
          notification.error({
            message: errorMsg,
          })
        }
      }
    })
	}

	validateConfSenha = (rule, value, callback) => {
		const { getFieldValue } = this.props.form;
		if (value !== getFieldValue('senha')) {
			callback('Confirmação inválida');
		}

		callback();
	}

  render() {
    const { getFieldDecorator } = this.props.form;
    const { token } = this.props;

    return (
      <Fragment>
        <Sticky inside={true} />
        <Hero>
          {!token ? (
            <Form onSubmit={this.handleSubmit} className="login-form">
              <FormItem>
                {getFieldDecorator('username', {
                  rules: [
                    { type: 'email', message: 'Por favor digite um email válido' },
                    { required: true, message: 'Digite seu email' },
                  ],
                })(<Input size="default" placeholder="Email" />)}
              </FormItem>
              <div className="form-actions">
                <Button type="primary" htmlType="submit" className="btn-green">
                  <span>Recuperar Senha</span>
                </Button>
              </div>
              <div className="mb-2">
                <span>Lembrou sua senha? </span>
                <Link href="/login">
                  <a className="utils__link utils__link--underlined">
                    Entrar
                  </a>
                </Link>
              </div>
            </Form>
          ) : (
            <Form onSubmit={this.handleSubmitNewPassword} className="login-form">
              <FormItem>
                {getFieldDecorator('senha', {
                  rules: [
                    { required: true, message: 'Digite sua senha' },
                  ],
                })(<Input size="default" type="password" placeholder="Nova Senha" />)}
              </FormItem>
              <FormItem>
                {getFieldDecorator('confSenha', {
                  rules: [
                    { validator: this.validateConfSenha },
                  ],
                })(<Input size="default" type="password" placeholder="Confirmar Senha" />)}
              </FormItem>
              <div className="form-actions">
                <Button type="primary" htmlType="submit" className="btn-green">
                  <span>Redefinir Senha</span>
                </Button>
              </div>
            </Form>
          )}
        </Hero>
        <Footer />
      </Fragment>
    );
  }
}

const ForgotPasswordComponentForm = Form.create()(ForgotPasswordComponent)
export default ForgotPasswordComponentForm

