import React, {Component, Fragment} from "react";
import { Form, Input, Modal, Button, message, notification } from 'antd';
import moment from 'moment'
import Cookie from 'js-cookie'
import api from "../../services/api";

import { Professional, InfosModal } from "./styles";
import Router from "next/dist/lib/router";
import {Hero} from "./styles";

const FormItem = Form.Item

class HorariosProfissionais extends Component {

  state = {
    visible: false,
    visibleLogin: false,
    horario: '',
  }

  componentDidUpdate(prevProps) {
        if (prevProps.profissional != this.props.profissional) {
        }
  }

  showModal = (horario) => {
    this.setState({
      visible: true,
      horario: horario
    });
  }

    showModalLogin = (horario) => {
        this.setState({
            visibleLogin: true,
            horario: horario
        });
    }

  handleCancel = () => {
    this.setState({
      visible: false
    });
  };

    handleCancelLogin = () => {
        this.setState({
            visibleLogin: false
        });
    };

  handleSubmit = e => {
    e.preventDefault();
    this.props.form.validateFields((err, values) => {
        if (!err) {
            console.log('Received values of form: ', values);

            var data = {
                grant_type: 'password',
                client_id: values.email,
                username: values.email,
                password: values.password,
                scope: '',
            }

            api.post(`/oauth`, data)
                .then(response => {

                    const expiresInM = response.data.expires_in
                    const expiresAt = new Date().getTime() + parseInt(expiresInM, 10) * 1000 - 60000;
                    var in30Minutes = 1/48;

                    Cookie.set('app.access_token', response.data.access_token, { expires: in30Minutes })
                    Cookie.set('app.refresh_token', response.data.refresh_token, { expires: in30Minutes })
                    Cookie.set('app.Role', 'client', { expires: in30Minutes })
                    Cookie.set('app.userName', values.email, { expires: in30Minutes })
                    Cookie.set('app.expires_in', response.data.expires_in, { expires: in30Minutes })
                    Cookie.set('app.expires_at', expiresAt, { expires: in30Minutes })

                    notification.success({
                        message: 'Logado com sucesso!'
                    })

                    api.get('/clientes/me', {
                        headers: { Authorization: "Bearer " + response.data.access_token }
                    }).then(res => {
                        Cookie.set('app.userId', res.data.id, { expires: in30Minutes })
                        console.log(res.data.id);
                        this.handleCancelLogin();
                        this.showModal(this.state.horario);
                    }).catch(err => {
                        console.log('não logou id');
                        console.log(err);
                    })
                })
                .catch(res => {
                    message.error('Email ou senha incorretos')
                    console.log(res);
                    e.preventDefault();
                })
        }
    });
  };

  handleOk = () => {

    const id = Cookie.get('app.userId');

      if (typeof id !== 'undefined') {
        const date = this.props.horario;
        const dataFormatada = moment(date,'DD/MM/YYYY').format('YYYY-MM-DD');

        const data = {
            status: "Aguardando confirmação",
            dataHora: `${dataFormatada} ${this.state.horario}:00`,
            motivoCancelamento: null,
            profissional: this.props.idProfissional,
            cliente: id,
            agendamentoExterno: true,
            servicos: {
                id: this.props.idServico
            }
        }

        api.post(`/clinicas/${this.props.idClinica}/agendas`, data, {
            headers: {Authorization: "Bearer " + Cookie.get('app.access_token')}
        }).then(res => {
            console.log(res.data);
            notification.success({
                message: 'Agendado com sucesso!'
            })
            Router.push('/perfil/me/agenda')
        }).catch(err => {
            if (err.response && err.response.data) {
                notification.error({
                    message: 'Agendamento não efetivado!',
                    description: err.response.data.detail
                })
            } else {
                console.log(JSON.stringify(err));
            }
        })
      } else {
          this.logout()
          this.showModalLogin(this.state.horario);
      }
  }

    logout = () => {
        notification.error({
            message: 'Sessão expirada!'
        })

        setTimeout(
            function () {
                Cookie.remove('app.access_token')
                Cookie.remove('app.refresh_token')
                Cookie.remove('app.Role', 'client')
                Cookie.remove('app.userName')
                Cookie.remove('app.expires_in')
                Cookie.remove('app.expires_at')
                Cookie.remove('app.userId')
            }
                .bind(this),
            2500
        );
    }

    getDiaSemanaAtual(calendar) {
        let data = calendar ? moment(calendar).isoWeekday() : '';
        switch (data) {
            case 1: data = 'Segunda-feira'; break;
            case 2: data = 'Terça-feira'; break;
            case 3: data = 'Quarta-feira'; break;
            case 4: data = 'Quinta-feira'; break;
            case 5: data = 'Sexta-feira'; break;
            case 6: data = 'Sábado'; break;
            case 7: data = 'Domingo'; break;
            default: data = '';
        };
        return data;
    }

    validaHorarioDisponivel(index, horario) {
        const data = this.props.horario;
        const agenda = this.props.agenda;
        const servico = this.props.idServico;
        const profissional = this.props.idProfissional;
        const profissionalIntervalos = this.props.profissional.profissionalIntervalos[0];

        var horarioIndisponivel = [];
        var agendamentoDoServico = 0;
        var agendamentoDoProfissional = 0;
        horarioIndisponivel['disabled'] = false;
        horarioIndisponivel['class'] = '';

        var horarioEscolhido = horario;

        if (profissionalIntervalos) {
            profissionalIntervalos.map((intervalo, index) => {
                if (intervalo.tipo == "Fixo") {
                    var dataFiltro = moment(data, 'DD/MM/YYYY');
                    var diaSemanaIntervaloFixo = this.getDiaSemanaAtual(dataFiltro);

                    // console.log('entrou: ' + diaSemanaIntervaloFixo+' == '+intervalo.diaSemanaTipoFixo);
                    if (diaSemanaIntervaloFixo == intervalo.diaSemanaTipoFixo) {
                        var intervaloInicio = moment(intervalo.dataHoraInicio.date).format('YYYY-MM-DD HH:mm');
                        var intervaloFim = moment(intervalo.dataHoraFim.date).format('YYYY-MM-DD HH:mm');
                        var dataIntervaloFixo = moment(intervalo.dataHoraInicio.date).format('YYYY-MM-DD');
                        var dataHorarioEscolhido = moment(dataIntervaloFixo,).format('YYYY-MM-DD') + ' ' + horarioEscolhido;
                        /*console.log(moment(data, 'DD/MM/YYYY').format('YYYY-MM-DD') + ' == ' + moment(intervaloInicio).format('YYYY-MM-DD') + ' && (' + moment(dataHorarioEscolhido).isSame(intervaloInicio) + ' || ' + moment(dataHorarioEscolhido).isSame(intervaloFim) + ' || ' + moment(dataHorarioEscolhido).isBetween(intervaloInicio, intervaloFim)+')');
                        console.log(dataHorarioEscolhido);
                        console.log(intervaloInicio);
                        console.log(intervaloFim);
                        console.log('-----------------------');*/
                        if ((moment(dataHorarioEscolhido).isSame(intervaloInicio) || moment(dataHorarioEscolhido).isSame(intervaloFim) || moment(dataHorarioEscolhido).isBetween(intervaloInicio, intervaloFim))) {
                            horarioIndisponivel['disabled'] = true;
                            horarioIndisponivel['class'] = 'btn-disabled';
                            // console.log('Intervalo Fixo: '+intervaloInicio + ' - ' + intervaloFim);
                        }
                    }
                } else {
                    var intervaloInicio = moment(intervalo.dataHoraInicio.date).format('YYYY-MM-DD HH:mm');
                    var intervaloFim = moment(intervalo.dataHoraFim.date).format('YYYY-MM-DD HH:mm');
                    var dataHorarioEscolhido = moment(data,'DD/MM/YYYY').format('YYYY-MM-DD') + ' ' + horarioEscolhido;
                    if (moment(data,'DD/MM/YYYY').format('YYYY-MM-DD') == moment(intervaloInicio).format('YYYY-MM-DD') && (moment(dataHorarioEscolhido).isSame(intervaloInicio) || moment(dataHorarioEscolhido).isSame(intervaloFim) || moment(dataHorarioEscolhido).isBetween(intervaloInicio, intervaloFim))) {
                        horarioIndisponivel['disabled'] = true;
                        horarioIndisponivel['class'] = 'btn-disabled';
                        //console.log('Intervalo Variável: ' +intervaloInicio + ' - ' + intervaloFim);
                    }
                }
            })
        }

        if(agenda) {
            agenda.map((agendamento, index) => {
                if(agendamento.profissional.id === profissional) {
                    agendamentoDoProfissional = 1;
                } else {
                    agendamentoDoProfissional = 0;
                }

                var tempoAgendamento = 0;
                var agendamentoInicio = moment(agendamento.dataHora.date).format('YYYY-MM-DD HH:mm');
                agendamento.servicos.map((servicosAgendamento, index) => {
                    if(servicosAgendamento.id === servico) {
                        agendamentoDoServico = 1;
                    } else {
                        agendamentoDoServico = 0;
                    }
                    tempoAgendamento = tempoAgendamento + servicosAgendamento.tempoMedioDuracao;
                })
                var agendamentoFim = moment(agendamentoInicio).add(tempoAgendamento, 'm').format('YYYY-MM-DD HH:mm');

                if(agendamentoDoServico === 1 || agendamentoDoProfissional === 1) {
                    var dataHorarioEscolhido = moment(data, 'DD/MM/YYYY').format('YYYY-MM-DD') + ' ' + horarioEscolhido;
                    if (moment(data, 'DD/MM/YYYY').format('YYYY-MM-DD') == moment(agendamentoInicio).format('YYYY-MM-DD') && (moment(dataHorarioEscolhido).isSame(agendamentoInicio) || moment(dataHorarioEscolhido).isSame(agendamentoFim) || moment(dataHorarioEscolhido).isBetween(agendamentoInicio, agendamentoFim))) {
                        horarioIndisponivel['disabled'] = true;
                        horarioIndisponivel['class'] = 'btn-disabled';
                        // console.log('Agendamento: ' +agendamentoInicio + ' - ' + agendamentoFim);
                    }
                }
            })
        }

        return horarioIndisponivel;
    }

  listarHorariosAgenda(horariosFormatados) {
     if(this.props.agendamentoExterno == false) {
       return null;
     }

     if (!horariosFormatados.length) {
       return <span style={{'color': '#00ba9e'}}>Não há horários disponíveis para a data selecionada</span>;
     }

     return horariosFormatados.map((horario, index) => {
       const horarioIndisponivel = this.validaHorarioDisponivel(index, horario);
       const classBtn = `btn btn-hours ${horarioIndisponivel['class']}`;
         return <button key={index} type="button" disabled={horarioIndisponivel['disabled']} className={classBtn} onClick={() => (Cookie.get('app.access_token')) ? this.showModal(horario) : this.showModalLogin(horario)}>
         <span>{horario}</span>
       </button>;
    })

  }

  render() {
      let horariosFormatados = [];
      let horarios = this.props.profissional.hasOwnProperty('horarios') && this.props.profissional.horarios.length && this.props.profissional.horarios[0].find(horario => horario && horario.nome == this.props.dataHorario);
      if (horarios && horarios.inicio && horarios.fim) {
          let hrInicio = parseInt(String(horarios.inicio).split(':')[0]);
          let minInicio = parseInt(String(horarios.inicio).split(':')[1]);
          let hrFim = parseInt(String(horarios.fim).split(':')[0]);
          let minFim = parseInt(String(horarios.fim).split(':')[1]);
          let hora;
          let hora2;

          for (var i = hrInicio; i < hrFim; i++) {
              hora = (i < 10) ? '0' + i : i;
              if (minInicio === 0) {
                  horariosFormatados.push(hora + ':00');
                  if (hrFim !== i) {
                      horariosFormatados.push(hora + ':30');
                  }
              } else {
                  hora2 = ((i + 1) < 10) ? '0' + (i + 1) : (i + 1);
                  horariosFormatados.push(hora + ':30');
                  if (hrFim !== (i + 1) || (hrFim === (i + 1) && minFim === 30)) {
                      horariosFormatados.push((hora2) + ':00');
                  }
              }
          }
      }

    const data = this.props.horario;
    const dataFormatada = data;
    const { getFieldDecorator } = this.props.form;

    return (
        <Professional>
            <div className="infos-professional">
                <h4 className="name-professional">
                    {this.props.servico}
                </h4>
                <div className="hours">
                { this.listarHorariosAgenda(horariosFormatados) }
                </div>
                <Modal
                    title='Confirmar agendamento'
                    visible={this.state.visible}
                    onOk={this.handleOk}
                    onCancel={this.handleCancel}
                    closable={false}
                    width={'65%'}
                    footer={[
                        <Button key="ok" onClick={this.handleOk} className="btn btn-green">
                            Confirmar
                        </Button>,
                    ]}
                    centered
                >
                    <InfosModal>
                        <div className="infos">
                            <p className="date">
                                <span>Data e horário:</span> {moment(dataFormatada,'DD/MM/YYYY').format('dddd, D [de] MMMM [de] YYYY')},
                                às {this.state.horario}</p>
                            <p className="clinic"><span>Local:</span> {this.props.clinica}</p>
                            <p className="service"><span>Serviço:</span> {this.props.servico}</p>
                            <p className="professional"><span>Profissional:</span> {this.props.profissional.nome}
                            </p>
                        </div>
                    </InfosModal>
                </Modal>

                <Modal
                    title='Fazer Login'
                    visible={this.state.visibleLogin}
                    onCancel={this.handleCancelLogin}
                    closable={false}
                    width={'65%'}
                    footer={[]}
                    centered
                >
                    <InfosModal>
                        <Hero>
                            <Form onSubmit={this.handleSubmit} className="login-form">
                                <FormItem>
                                    {getFieldDecorator('email', {
                                        rules: [
                                            // { type: 'email', message: 'Por favor digite um email válido' },
                                            { required: true, message: 'Digite seu usuário' },
                                        ],
                                    })(<Input size="default" placeholder="Email" />)}
                                </FormItem>
                                <FormItem>
                                    {getFieldDecorator('password', {
                                        rules: [{ required: true, message: 'Digite sua senha' }],
                                    })(<Input size="default" type="password" placeholder="Senha" />)}
                                </FormItem>
                                <div className="form-actions">
                                    <Button type="primary" htmlType="submit" className="btn-green">
                                        <span>Login</span>
                                    </Button>
                                </div>
                                <div className="mb-2">
                                    <span>Não tem uma conta? </span>
                                    <a href="/cadastro" className="utils__link utils__link--underlined">
                                        Registre-se
                            </a>
                                </div>
                            </Form>
                        </Hero>
                    </InfosModal>
                </Modal>
            </div>
        </Professional>
    );
  }
}

const HorariosProfissionaisForm = Form.create()(HorariosProfissionais);
export default HorariosProfissionaisForm;

import React, { Component, Fragment } from 'react'
import { Form, Input, Modal, Button, message, notification } from 'antd'
import moment from 'moment'
import Cookie from 'js-cookie'
import api from '../../services/api'

import { Professional, InfosModal } from './styles'
import Router from 'next/dist/lib/router'
import { Hero } from './styles'

const FormItem = Form.Item

class Horarios extends Component {
	state = {
		visible: false,
		visibleLogin: false,
		horario: '',
	}

	componentDidUpdate(prevProps) {
		if (prevProps.profissional != this.props.profissional) {
			console.log(this.props.profissional)
		}
	}

	showModal = horario => {
		this.setState({
			visible: true,
			horario: horario,
		})
	}

	showModalLogin = horario => {
		this.setState({
			visibleLogin: true,
			horario: horario,
		})
	}

	handleCancel = () => {
		this.setState({
			visible: false,
		})
	}

	handleCancelLogin = () => {
		this.setState({
			visibleLogin: false,
		})
	}

	handleSubmit = e => {
		e.preventDefault()
		this.props.form.validateFields((err, values) => {
			if (!err) {
				console.log('Received values of form: ', values)

				var data = {
					grant_type: 'password',
					client_id: values.email,
					username: values.email,
					password: values.password,
					scope: '',
				}

				api
					.post(`/oauth`, data)
					.then(response => {
						const expiresInM = response.data.expires_in
						const expiresAt =
							new Date().getTime() + parseInt(expiresInM, 10) * 1000 - 60000
						var in30Minutes = 1 / 48

						Cookie.set('app.access_token', response.data.access_token, {
							expires: in30Minutes,
						})
						Cookie.set('app.refresh_token', response.data.refresh_token, {
							expires: in30Minutes,
						})
						Cookie.set('app.Role', 'client', { expires: in30Minutes })
						Cookie.set('app.userName', values.email, { expires: in30Minutes })
						Cookie.set('app.expires_in', response.data.expires_in, {
							expires: in30Minutes,
						})
						Cookie.set('app.expires_at', expiresAt, { expires: in30Minutes })

						notification.success({
							message: 'Logado com sucesso!',
						})
						api
							.get('/clientes/me', {
								headers: { Authorization: 'Bearer ' + response.data.access_token },
							})
							.then(res => {
								Cookie.set('app.userId', res.data.id, { expires: in30Minutes })
								this.handleCancelLogin()
								this.showModal(this.state.horario)
							})
							.catch(err => {
								console.log('não logou id')
								console.log(err)
							})
					})
					.catch(res => {
						message.error('Email ou senha incorretos')
						console.log(res)
						e.preventDefault()
					})
			}
		})
	}

	handleOk = () => {
		const id = Cookie.get('app.userId')

		if (typeof id !== 'undefined') {
			const date = this.props.horario
			const dataFormatada = moment(date, 'DD/MM/YYYY').format('YYYY-MM-DD')

			const data = {
				status: 'Aguardando confirmação',
				dataHora: `${dataFormatada} ${this.state.horario}:00`,
				motivoCancelamento: null,
				profissional: this.props.idProfissional,
				cliente: id,
				agendamentoExterno: true,
				servicos: [
					{
						servico: this.props.idServico,
					},
				],
			}
			console.log(this.state, this.props, data)

			api
				.post(`/clinicas/${this.props.idClinica}/agendas`, data, {
					headers: { Authorization: 'Bearer ' + Cookie.get('app.access_token') },
				})
				.then(res => {
					console.log(res.data)
					notification.success({
						message: 'Agendado com sucesso!',
					})
					Router.push('/perfil/me/agenda')
				})
				.catch(err => {
					if (err.response && err.response.data) {
						notification.error({
							message: 'Agendamento não efetivado!',
							description: err.response.data.detail,
						})
						console.log(JSON.stringify(err))
					} else {
						console.log(JSON.stringify(err))
					}
				})
		} else {
			this.logout()
			this.showModalLogin(this.state.horario)
		}
	}

	logout = () => {
		notification.error({
			message: 'Sessão expirada!',
		})

		setTimeout(
			function() {
				Cookie.remove('app.access_token')
				Cookie.remove('app.refresh_token')
				Cookie.remove('app.Role', 'client')
				Cookie.remove('app.userName')
				Cookie.remove('app.expires_in')
				Cookie.remove('app.expires_at')
				Cookie.remove('app.userId')
			}.bind(this),
			2500
		)
	}

	getDiaSemanaAtual(calendar) {
		let data = calendar ? moment(calendar).isoWeekday() : ''
		switch (data) {
			case 1:
				data = 'Segunda-feira'
				break
			case 2:
				data = 'Terça-feira'
				break
			case 3:
				data = 'Quarta-feira'
				break
			case 4:
				data = 'Quinta-feira'
				break
			case 5:
				data = 'Sexta-feira'
				break
			case 6:
				data = 'Sábado'
				break
			case 7:
				data = 'Domingo'
				break
			default:
				data = ''
		}
		return data
	}

	validaHorarioDisponivel(index, horario) {
		const data = this.props.horario
		const agenda = this.props.agenda
		const servico = this.props.idServico
		const profissional = this.props.idProfissional
		const profissionalIntevalos = this.props.profissional.profissionalIntervalos

		var horarioIndisponivel = []
		var agendamentoDoServico = 0
		var agendamentoDoProfissional = 0
		horarioIndisponivel['disabled'] = false
		horarioIndisponivel['class'] = ''

		var horarioEscolhido = horario

		if (profissionalIntevalos) {
			profissionalIntevalos.map((intervalo, index) => {
				if (intervalo.tipo == 'Fixo') {
					var dataFiltro = moment.utc(data, 'Do MMM YYYY')
					var diaSemanaIntervaloFixo = this.getDiaSemanaAtual(dataFiltro)
					//console.log('entrou: ' + diaSemanaIntervaloFixo+' == '+intervalo.diaSemanaTipoFixo);
					if (diaSemanaIntervaloFixo == intervalo.diaSemanaTipoFixo) {
						var intervaloInicio = moment(intervalo.dataHoraInicio.date).format(
							'YYYY-MM-DD HH:mm'
						)
						var intervaloFim = moment(intervalo.dataHoraFim.date).format(
							'YYYY-MM-DD HH:mm'
						)
						var dataIntervaloFixo = moment(intervalo.dataHoraInicio.date).format(
							'YYYY-MM-DD'
						)
						var dataHorarioEscolhido =
							moment(dataIntervaloFixo).format('YYYY-MM-DD') + ' ' + horarioEscolhido
						/* console.log(
							moment(data, 'DD/MM/YYYY').format('YYYY-MM-DD') +
								' == ' +
								moment(intervaloInicio).format('YYYY-MM-DD') +
								' && (' +
								moment(dataHorarioEscolhido).isSame(intervaloInicio) +
								' || ' +
								moment(dataHorarioEscolhido).isSame(intervaloFim) +
								' || ' +
								moment(dataHorarioEscolhido).isBetween(intervaloInicio, intervaloFim) +
								')'
						)
						console.log(dataHorarioEscolhido)
						console.log(intervaloInicio)
						console.log(intervaloFim) */
						if (
							moment(dataHorarioEscolhido).isSame(intervaloInicio) ||
							moment(dataHorarioEscolhido).isSame(intervaloFim) ||
							moment(dataHorarioEscolhido).isBetween(intervaloInicio, intervaloFim)
						) {
							horarioIndisponivel['disabled'] = true
							horarioIndisponivel['class'] = 'btn-disabled'
							// console.log('Intervalo Fixo: ' + intervaloInicio + ' - ' + intervaloFim)
						}
					}
				} else {
					var intervaloInicio = moment(intervalo.dataHoraInicio.date).format(
						'YYYY-MM-DD HH:mm'
					)
					var intervaloFim = moment(intervalo.dataHoraFim.date).format('YYYY-MM-DD HH:mm')
					var dataHorarioEscolhido =
						moment(data, 'DD/MM/YYYY').format('YYYY-MM-DD') + ' ' + horarioEscolhido
					if (
						moment(data, 'DD/MM/YYYY').format('YYYY-MM-DD') ==
							moment(intervaloInicio).format('YYYY-MM-DD') &&
						(moment(dataHorarioEscolhido).isSame(intervaloInicio) ||
							moment(dataHorarioEscolhido).isSame(intervaloFim) ||
							moment(dataHorarioEscolhido).isBetween(intervaloInicio, intervaloFim))
					) {
						horarioIndisponivel['disabled'] = true
						horarioIndisponivel['class'] = 'btn-disabled'
						// console.log('Intervalo Variável: ' + intervaloInicio + ' - ' + intervaloFim)
					}
				}
			})
		}

		if (agenda) {
			agenda.map((agendamento, index) => {
				if (agendamento.profissional.id === profissional) {
					agendamentoDoProfissional = 1
				} else {
					agendamentoDoProfissional = 0
				}

				var tempoAgendamento = 0
				var agendamentoInicio = moment(agendamento.dataHora.date).format(
					'YYYY-MM-DD HH:mm'
				)
				agendamento.servicos.map((servicosAgendamento, index) => {
					if (servicosAgendamento.id === servico) {
						agendamentoDoServico = 1
					} else {
						agendamentoDoServico = 0
					}
					tempoAgendamento = tempoAgendamento + servicosAgendamento.tempoMedioDuracao
				})
				var agendamentoFim = moment(agendamentoInicio)
					.add(tempoAgendamento, 'm')
					.format('YYYY-MM-DD HH:mm')

				if (agendamentoDoServico === 1 || agendamentoDoProfissional === 1) {
					var dataHorarioEscolhido =
						moment(data, 'DD/MM/YYYY').format('YYYY-MM-DD') + ' ' + horarioEscolhido
					if (
						moment(data, 'DD/MM/YYYY').format('YYYY-MM-DD') ==
							moment(agendamentoInicio).format('YYYY-MM-DD') &&
						(moment(dataHorarioEscolhido).isSame(agendamentoInicio) ||
							moment(dataHorarioEscolhido).isSame(agendamentoFim) ||
							moment(dataHorarioEscolhido).isBetween(agendamentoInicio, agendamentoFim))
					) {
						horarioIndisponivel['disabled'] = true
						horarioIndisponivel['class'] = 'btn-disabled'
						// console.log('Agendamento: ' + agendamentoInicio + ' - ' + agendamentoFim)
					}
				}
			})
		}

		return horarioIndisponivel
	}

	listarHorariosAgenda(horariosFormatados) {
		if (this.props.agendamentoExterno == false) {
			return null
		}

		if (!horariosFormatados.length) {
			return (
				<span style={{ color: '#00ba9e' }}>
					Não há horários disponíveis para a data selecionada
				</span>
			)
		}

		return horariosFormatados.map((horario, index) => {
			const horarioIndisponivel = this.validaHorarioDisponivel(index, horario)
			const classBtn = `btn btn-hours ${horarioIndisponivel['class']}`
			return (
				<button
					key={index}
					type="button"
					disabled={horarioIndisponivel['disabled']}
					className={classBtn}
					onClick={() =>
						Cookie.get('app.access_token')
							? this.showModal(horario)
							: this.showModalLogin(horario)
					}
				>
					<span>{horario}</span>
				</button>
			)
		})
	}

	exibirFotoProfissional() {
		if (
			this.props.profissional &&
			this.props.profissional.foto &&
			this.props.profissional.foto.tmp_name
		) {
			return (
				<img
					src={this.props.profissional.foto.tmp_name.replace(
						's3://',
						'//s3.amazonaws.com/'
					)}
					alt={this.props.profissional.nome}
				/>
			)
		} else {
			return <img src="/static/user.svg" alt="" />
		}
	}

	render() {
		let horariosFormatados = []
		let horarios =
			this.props.profissional.hasOwnProperty('horarios') &&
			this.props.profissional.horarios.length &&
			this.props.profissional.horarios.find(
				horario => horario && horario.nome == this.props.dataHorario
			)
		if (horarios && horarios.inicio && horarios.fim) {
			let hrInicio = parseInt(String(horarios.inicio).split(':')[0])
			let minInicio = parseInt(String(horarios.inicio).split(':')[1])
			let hrFim = parseInt(String(horarios.fim).split(':')[0])
			let minFim = parseInt(String(horarios.fim).split(':')[1])
			let hora
			let hora2

			for (var i = hrInicio; i < hrFim; i++) {
				hora = i < 10 ? '0' + i : i
				if (minInicio === 0) {
					horariosFormatados.push(hora + ':00')
					if (hrFim !== i) {
						horariosFormatados.push(hora + ':30')
					}
				} else {
					hora2 = i + 1 < 10 ? '0' + (i + 1) : i + 1
					horariosFormatados.push(hora + ':30')
					if (hrFim !== i + 1 || (hrFim === i + 1 && minFim === 30)) {
						horariosFormatados.push(hora2 + ':00')
					}
				}
			}
		}

		const data = this.props.horario

		const dataFormatada = data
		const { getFieldDecorator } = this.props.form

		return (
			<Professional>
				<div className="img-professional">{this.exibirFotoProfissional()}</div>
				<div className="infos-professional">
					<h4 className="name-professional">
						{this.props.profissional.nome} -{' '}
						<span>
							{String(this.props.profissional.nomeConselho).toUpperCase()}:{' '}
							{this.props.profissional.numeroRegistro}
						</span>
					</h4>
					<div className="hours">{this.listarHorariosAgenda(horariosFormatados)}</div>
					<Modal
						title="Confirmar agendamento"
						visible={this.state.visible}
						onOk={this.handleOk}
						onCancel={this.handleCancel}
						closable={false}
						width={'65%'}
						footer={[
							<Button key="ok" onClick={this.handleOk} className="btn btn-green">
								Confirmar
							</Button>,
						]}
						centered
					>
						<InfosModal>
							<div className="infos">
								<p className="date">
									<span>Data e horário:</span>{' '}
									{moment(dataFormatada, 'DD/MM/YYYY').format(
										'dddd, D [de] MMMM [de] YYYY'
									)}
									, às {this.state.horario}
								</p>
								<p className="clinic">
									<span>Local:</span> {this.props.clinica}
								</p>
								<p className="service">
									<span>Serviço:</span> {this.props.servico}
								</p>
								<p className="professional">
									<span>Profissional:</span> {this.props.profissional.nome}
								</p>
							</div>
						</InfosModal>
					</Modal>

					<Modal
						title="Fazer Login"
						visible={this.state.visibleLogin}
						onCancel={this.handleCancelLogin}
						closable={false}
						width={'65%'}
						footer={[]}
						centered
					>
						<InfosModal>
							<Hero>
								<Form onSubmit={this.handleSubmit} className="login-form">
									<FormItem>
										{getFieldDecorator('email', {
											rules: [
												// { type: 'email', message: 'Por favor digite um email válido' },
												{ required: true, message: 'Digite seu usuário' },
											],
										})(<Input size="default" placeholder="Email" />)}
									</FormItem>
									<FormItem>
										{getFieldDecorator('password', {
											rules: [{ required: true, message: 'Digite sua senha' }],
										})(<Input size="default" type="password" placeholder="Senha" />)}
									</FormItem>
									<div className="form-actions">
										<Button type="primary" htmlType="submit" className="btn-green">
											<span>Login</span>
										</Button>
									</div>
									<div className="mb-2">
										<span>Não tem uma conta? </span>
										<a href="/cadastro" className="utils__link utils__link--underlined">
											Registre-se
										</a>
									</div>
								</Form>
							</Hero>
						</InfosModal>
					</Modal>
				</div>
			</Professional>
		)
	}
}

