// import { Creators as ClienteActions } from "../../store/ducks/cliente";
// import { connect } from "react-redux";
// import { bindActionCreators } from "redux";
import MaskedInput from 'react-text-mask'
import ViaCep from 'react-via-cep'
import Cookie from 'js-cookie'
import api from '../../services/api'

const FormItem = Form.Item
const Option = Select.Option
const { TextArea } = Input

let id = 0
let initialState = {
	confirmDirty: false,
	estadoCivil: '',
	genero: '',
	dataNascimento: '',
	data: {},
	idUsuario: null,
	username: '',
	idEndereco: null,
	idTelefones: [],
	numeroPreferencial: null,
	modalTermosDeConsentimento: false,
	modalTermosDeUso: false,
	modalPoliticaPrivacidade: false,
	modalConfirmaTermos: false,
}

class PerfilComponent extends Component {
	constructor(props) {
		super(props)
		this.state = {
			...initialState,
			cep: '',
			cepCidade: '',
			cepEstado: '',
			current: 0,
			phoneNumbers: [],
			phoneQtd: 0,
			loading: true,
		}

		this.handleChangeCep = this.handleChangeCep.bind(this)
		this.handleSuccess = this.handleSuccess.bind(this)
		this.modalTermosDeConsentimento = this.modalTermosDeConsentimento.bind(this)
		this.modalTermosDeUso = this.modalTermosDeUso.bind(this)
		this.modalPoliticaPrivacidade = this.modalPoliticaPrivacidade.bind(this)
		this.modalConfirmaTermos = this.modalConfirmaTermos.bind(this)
	}

	logout() {
		Cookie.remove('app.access_token')
		Cookie.remove('app.refresh_token')
		Cookie.remove('app.Role', 'client')
		Cookie.remove('app.userName')
		Cookie.remove('app.expires_in')
		Cookie.remove('app.expires_at')
		Cookie.remove('app.userId')

		window.location.href = '/login'
	}

	componentWillMount() {
		this.setState({ loading: true })
	}

	componentDidMount(prevProps) {
		if (!Cookie.get('app.access_token')) {
			this.logout()
		} else {
			this.setState({ idClient: 'me' })

			var config = {
				headers: { Authorization: `Bearer ${Cookie.get('app.access_token')}` },
			}

			api
				.get(`/clientes/me`, config)
				.then(response => {
					const cliente = response.data
					console.log('cliente')
					console.log(cliente)

					this.setState({
						data: cliente,
						estadoCivil: cliente.estadoCivil,
						genero: cliente.genero,
						dataNascimento: cliente.dataNascimento,
						idUsuario: cliente.id,
						username: cliente.username,
						idEndereco: cliente.endereco ? cliente.endereco.id : null,
						idTelefone: cliente.telefones[0].id,
						numeroPreferencial: cliente.telefones[0].preferencial,
						cep: cliente.endereco ? cliente.endereco.cep : null,
						termosAceitos: cliente.termosAceitos,
					})
					var phonePref = this.formatTelefone(cliente.telefones[0].numero)
					document.getElementById(`telefones[0]`).value = phonePref

					const arr = []
					const arrQtd = []
					const idPhones = []

					for (let i = 1; i < cliente.telefones.length; i++) {
						arr.push(cliente.telefones[i].numero)
						arrQtd.push(i)
						idPhones.push(cliente.telefones[i].id)
						this.add()

						const numberString = this.formatTelefone(cliente.telefones[i].numero)
						document.getElementById(`telefones[${i}]`).value = numberString
					}

					this.setState({ phoneNumbers: arr, phoneQtd: arrQtd, idTelefones: idPhones })

					// Mascara para cpf responsável
					const pt1 = cliente.cpf.substring(0, 3)
					const pt2 = cliente.cpf.substring(3, 6)
					const pt3 = cliente.cpf.substring(6, 9)
					const pt4 = cliente.cpf.substring(9, 11)
					const cpfComplete = pt1 + '.' + pt2 + '.' + pt3 + '-' + pt4

					// Mascara CEP
					const cep1 = cliente.endereco.cep.substring(0, 5)
					const cep2 = cliente.endereco.cep.substring(5, 8)
					const cepCompleto = cep1 + '-' + cep2
					if (cliente.dataNascimento === null) {
						this.props.form.setFieldsValue({
							nome: cliente.nome,
							email: cliente.email,
							cidade: cliente.endereco.cidade,
							uf: cliente.endereco.uf,
							telefone: cliente.telefones[0].numero,
							cpf: cpfComplete,
							cep: cepCompleto,
							logradouro: cliente.endereco.logradouro,
							numero: cliente.endereco.numero,
							bairro: cliente.endereco.bairro,
							complemento: cliente.endereco.complemento,
							convenios: cliente.convenios,
							dataNascimento: null,
							dependentes: cliente.nomeDependentes,
							termosAceitos: cliente.termosAceitos,
						})
					} else {
						const nascimento = cliente.dataNascimento.date
						const dataFinal = nascimento.substring(0, 10)
						const dataSplit = dataFinal.split('-')
						const dataFinalMesmo = dataSplit[2] + '/' + dataSplit[1] + '/' + dataSplit[0]
						this.props.form.setFieldsValue({
							nome: cliente.nome,
							email: cliente.email,
							cidade: cliente.endereco.cidade,
							uf: cliente.endereco.uf,
							telefone: cliente.telefones[0].numero,
							cpf: cpfComplete,
							cep: cepCompleto,
							logradouro: cliente.endereco.logradouro,
							numero: cliente.endereco.numero,
							bairro: cliente.endereco.bairro,
							complemento: cliente.endereco.complemento,
							convenios: cliente.convenios,
							dataNascimento: dataFinalMesmo,
							dependentes: cliente.nomeDependentes,
							termosAceitos: cliente.termosAceitos,
						})
					}

					this.setState({ loading: false })
				})
				.catch(err => {
					console.log('erro')
					console.log(err)

					if (err && err.response && err.response.status && err.response.status === 401) {
						this.logout()
					}
				})
		}
	}

