	handleConfirmBlur = e => {
		const value = e.target.value
		this.setState({ confirmDirty: this.state.confirmDirty || !!value })
	}

	remove = k => {
		const { form } = this.props
		// can use data-binding to get
		const keys = form.getFieldValue('keys')
		// We need at least one passenger
		if (keys.length === 1) {
			return
		}

		// can use data-binding to set
		form.setFieldsValue({
			keys: keys.filter(key => key !== k),
		})
	}

	add = () => {
		const { form } = this.props
		// can use data-binding to get
		const keys = form.getFieldValue('keys')
		const nextKeys = keys.concat(++id)
		// can use data-binding to set
		// important! notify form to detect changes
		form.setFieldsValue({
			keys: nextKeys,
		})
	}

	save() {
		const dados = this.state.data
		delete dados.user
		delete dados._links
		delete dados.email
		delete dados.clinicas
		delete dados.agendas
		delete dados.origem
		delete dados.entity
		delete dados.username
		delete dados.dataHoraAceite

		var config = {
			headers: { Authorization: `Bearer ${Cookie.get('app.access_token')}` },
		}

		api
			.patch(`/clientes/me`, dados, config)
			.then(res => {
				notification.success({
					message: 'Alterado com sucesso!',
				})

				setTimeout(
					function() {
						window.location.href = '/perfil/me/dados'
					}.bind(this),
					2500
				)
			})
			.catch(error => {
				this.setState({ loading: false })
				this.returnMsg(error.response)
			})
	}

	getDateTimeArray(data) {
		var schedule = new Date(data)
		var arrayData = []
		var meses = [
			'Jan',
			'Fev',
			'Mar',
			'Abr',
			'Mai',
			'Jun',
			'Jul',
			'Ago',
			'Set',
			'Out',
			'Nov',
			'Dez',
		]

		arrayData['dia'] = schedule.getDate()
		arrayData['mes'] = meses[schedule.getMonth()]
		arrayData['ano'] = schedule.getFullYear()
		arrayData['hora'] =
			schedule.getHours() < 10 ? '0' + schedule.getHours() : schedule.getHours()
		arrayData['minuto'] =
			schedule.getUTCMinutes() < 10
				? '0' + schedule.getUTCMinutes()
				: schedule.getUTCMinutes()

		return arrayData
	}

	formatTelefone(telefone) {
		const ddd = telefone.substring(0, 2)
		const number1 = telefone.substring(2, 7)
		const number2 = telefone.substring(7, 11)

		const numberString = '(' + ddd + ') ' + number1 + '-' + number2

		return numberString
	}

	returnMsg(responseData) {
		if (responseData !== undefined) {
			const msgs = []
			const arrResults = []

			if (responseData.status === 400) {
				var erros = []
				erros[0] = []
				erros[0][0] = responseData.data.detail
			} else {
				var erros = responseData.data.validation_messages
			}

			const arrFields = Object.keys(erros)

			if (responseData.status !== 200 && responseData.status !== 201) {
				const results = Object.values(erros)

				for (var i = 0; i < results.length; i++) {
					arrResults.push([results[i]])
				}

				for (i = 0; i < arrFields.length; i++) {
					if (typeof arrResults[i] === 'string' || arrResults[i] instanceof String) {
						var objresult = arrResults[i]
					} else {
						const msgresult = Object.values(arrResults[i][0])
						if (typeof msgresult[0] === 'string' || msgresult[0] instanceof String) {
							objresult = msgresult[0]
						} else {
							objresult = Object.values(msgresult[0])
						}
					}

					if (typeof objresult === 'string' || objresult instanceof String) {
						var retorno = objresult
					} else if (typeof objresult[0] === 'string' || objresult[0] instanceof String) {
						retorno = objresult[0]
					} else {
						const objresult2 = Object.values(objresult[0])
						retorno = ''
						for (i = 0; i < objresult2.length; i++) {
							retorno += objresult2[i] + ' | '
						}
					}
					msgs.push([
						{
							status: responseData.status,
							field: 'Erro ao alterar!',
							message: retorno,
							type: 'error',
						},
					])
				}
			}

			for (i = 0; i < msgs.length; i++) {
				const msgfinal = Object.entries(msgs[i])
				notification.error({
					message: msgfinal[0][1].field,
					description: msgfinal[0][1].message,
				})
			}
		}
	}

	handleSubmit = e => {
		e.preventDefault()

		this.props.form.validateFields((err, values) => {
			console.log(values)
			console.log(err)
			if (!err) {
				this.setState({ loading: true })

				const data = { ...this.state.data }

				// data.id = this.state.idClient
				data.nome = values['nome']
				if (values['dataNascimento']) {
					var nascimento2 = values['dataNascimento']
					var dataSplit2 = nascimento2.split('/')
					var dataFinal2 = dataSplit2[2] + '-' + dataSplit2[1] + '-' + dataSplit2[0]

					data.dataNascimento = dataFinal2
				} else {
					data.dataNascimento = null
				}
				data.genero = values['genero']
				data.cpf = values['cpf']
				data.convenios = values['convenios']
				data.nomeDependentes = values['dependentes']
				data.termosAceitos = values['termosAceitos']
				// User
				// data.id = this.state.idUsuario
				// data.username = this.state.username
				// Fim User
				// Endereço
				data.endereco.id = this.state.idEndereco
				data.endereco.cep = values['cep']
				data.endereco.uf = values['uf']
				data.endereco.cidade = values['cidade']
				data.endereco.bairro = values['bairro']
				data.endereco.numero = values['numero']
				data.endereco.logradouro = values['logradouro']
				data.endereco.complemento = values['complemento']
				// Fim endereço
				// Telefone
				// data.telefones[0].id = this.state.idTelefone
				// data.telefones[0].numero = values['telefone']
				// data.telefones[0].preferencial = true
				// Fim telefone

				var phones = []

				for (var i = 0; i < values.telefones.length; i++) {
					if (document.getElementById(`telefones[${i}]`)) {
						const x = document.getElementById(`telefones[${i}]`).value
						const pt1 = x.substring(1, 3)
						const pt2 = x.substring(4, 10)
						const pt3 = x.substring(11, 15)
						const phoneWithSpace = pt1 + pt2 + pt3
						const phoneClear = phoneWithSpace.replace(/\s/g, '')

						if (i < this.state.data.telefones.length) {
							if (this.state.data.telefones[i].numero === phoneClear) {
								phones.push({
									id: this.state.data.telefones[i].id,
									numero: phoneClear,
									preferencial: this.state.data.telefones[i].preferencial,
								})
							} else {
								phones.push({
									id: this.state.data.telefones[i].id,
									numero: phoneClear,
									preferencial: this.state.data.telefones[i].preferencial,
								})
							}
						} else {
							phones.push({
								numero: phoneClear,
								preferencial: i === 0 ? true : false,
							})
						}
					}
				}

				data.telefones = phones

				this.setState({ data }, () => {
					this.save()
				})
			}
		})
	}

	onChangeDate(value, dateString) {}

	updateField(event) {
		const data = { ...this.state.data }
		if (event.target.name === 'cep') {
			data['endereco']['cep'] = parseInt(event.target.value, 10)
		} else if (event.target.name === 'cidade') {
			data['endereco']['cidade'] = event.target.value
		} else if (event.target.name === 'complemento') {
			data['endereco']['complemento'] = event.target.value
		} else if (event.target.name === 'logradouro') {
			data['endereco']['logradouro'] = event.target.value
		} else if (event.target.name === 'numero') {
			data['endereco']['numero'] = event.target.value
		} else if (event.target.name === 'bairro') {
			data['endereco']['bairro'] = event.target.value
		} else {
			data[event.target.name] = event.target.value
		}
		this.setState({ data })
		// console.log(this.state.data)
	}

	validateConfSenha = (rule, value, callback) => {
		const { getFieldValue } = this.props.form

		if (value !== getFieldValue('novaSenha')) {
			callback('As senhas não são iguais!')
		}

		callback()
	}

	handleSubmitNewPassword = e => {
		e.preventDefault()

		this.props.form.validateFields(async (err, values) => {
			if (!err) {
				const { id, username } = this.state.data.user
				const { novaSenha, confSenha } = values
				const { setFieldsValue } = this.props.form

				try {
					const config = {
						headers: { Authorization: `Bearer ${Cookie.get('app.access_token')}` },
					}

					await api.patch(
						'/clientes/me',
						{
							user: {
								id,
								username,
								password: novaSenha,
								verifyPassword: confSenha,
							},
						},
						config
					)

					setFieldsValue({
						novaSenha: '',
						confSenha: '',
					})

					notification.success({
						message: `Senha alterada com sucesso.`,
					})
				} catch (error) {
					let errorMsg = 'Erro ao tentar salvar!'
					if (error.response.status === 422) {
						errorMsg = error.response.detail
					}
					notification.error({
						message: errorMsg,
					})
				}
			} else {
				notification.error({
					message: 'Campos inválidos!',
				})
			}
		})
	}

