							)}
							{query.aba === 'agenda' && (
								<div className="container">
									{this.state.data.agendas && this.state.data.agendas.length > 0 ? (
										<div className="main-content">
											<h2>Lista de agendamentos</h2>

											{this.state.data.agendas
												.sort(
													(a, b) =>
														new Date(a.dataHora.date).getTime() -
														new Date(b.dataHora.date).getTime()
												)
												.reverse()
												.map((agenda, index) => (
													<div className="schedule" key={index}>
														{
															(arrayDataHora = this.getDateTimeArray(
																agenda.dataHora.date
															))
														}
														<div className="schedule-day">
															<div className="calendario">
																<div className="date">
																	<span className="binds" />
																	<span className="month">
																		{arrayDataHora['mes']}/{arrayDataHora['ano']}
																	</span>
																	<h1 className="day">{arrayDataHora['dia']}</h1>
																</div>
																<div className="hour">
																	<button type="button" className="btn btn-hours">
																		<span>
																			{arrayDataHora['hora']}:{arrayDataHora['minuto']}
																		</span>
																	</button>
																</div>
															</div>
														</div>
														<div className="schedule-description">
															<div className="top-info">
																<h2 className="schedule-title">
																	{agenda.clinica.nomeFantasia}
																</h2>
																<div className="schedule-profissional">
																	{agenda.profissional.nome}
																	<span className="registro">
																		{agenda.profissional.nomeConselho}:{' '}
																		{agenda.profissional.numeroRegistro}
																	</span>
																</div>
																<div className="schedule-address">
																	<i className="fas fa-map-marker-alt" />{' '}
																	{agenda.clinica.endereco.logradouro},{' '}
																	{agenda.clinica.endereco.numero} -{' '}
																	{agenda.clinica.endereco.bairro} -{' '}
																	{agenda.clinica.endereco.cidade} -{' '}
																	{agenda.clinica.endereco.uf}
																</div>
																<div className="schedule-phone">
																	<i className="fas fa-phone" />
																	{agenda.clinica.telefones.map((telefone, index) => (
																		<span className="telefone">
																			{this.formatTelefone(telefone.numero)}
																		</span>
																	))}
																</div>
																<div className="schedule-type">
																	{agenda.servicos.map((servico, index) => (
																		<button type="button" className="btn btn-services">
																			<span>{servico.servico.titulo}</span>
																		</button>
																	))}
																</div>
															</div>
														</div>
														<div className="schedule-status">
															<p className="schedule-status-txt">{agenda.status}</p>
														</div>
													</div>
												))}
										</div>
									) : (
										<div style={{ width: '100%' }}>
											<Alert message="Nenhum agendamento cadastrado!" type="error" />
										</div>
									)}
								</div>
							)}
							{query.aba === 'senha' && (
								<div className="container">
									<div className="main-content">
										<Form onSubmit={this.handleSubmitNewPassword} className="login-form">
											<div className="row">
												<div className="col-lg-4">
													<FormItem label="Nova Senha">
														{getFieldDecorator('novaSenha', {
															rules: [{ required: true, message: 'Campo Obrigatório!' }],
														})(
