																name="nome"
																// onChange={e => this.updateField(e)}
															/>
														)}
													</FormItem>
												</div>
												<div className="col-lg-4">
													<FormItem label="Confimar Senha">
														{getFieldDecorator('confSenha', {
															rules: [
																{ required: true, message: 'Campo Obrigatório!' },
																{ validator: this.validateConfSenha },
															],
														})(
															<Input
																prefix={
																	<Icon type="key" style={{ color: 'rgba(0,0,0,.25)' }} />
																}
																placeholder="Confirmar Nova Senha"
																type="password"
																name="nome"
																// onChange={e => this.updateField(e)}
															/>
														)}
													</FormItem>
												</div>

												<div className="col-lg-12" style={{ textAlign: 'right' }}>
													<Button
														style={{ marginLeft: '10px' }}
														htmlType="submit"
														className="btn-green"
													>
														Alterar
													</Button>
												</div>
											</div>
										</Form>
									</div>
								</div>
							)}
						</Container>
					</Fragment>
				)}

				<Footer />
			</Fragment>
		)
	}
}

