import React, { Component } from 'react'
import { MenuOutlined } from '@ant-design/icons'
import Link from 'next/link'
import Router from 'next/router'
import NProgress from 'nprogress'
import { isAuthenticate } from '../../services/auth'
import { Avatar, Dropdown, Menu, notification } from 'antd'
import Cookie from 'js-cookie'

import { Container } from './styles'

Router.onRouteChangeStart = () => {
	NProgress.start()
}
Router.onRouteChangeComplete = () => {
	NProgress.done()
}

Router.onRouteChangeError = () => {
	NProgress.done()
}

class Sticky extends Component {
	state = {
		small: false,
		innerWidth: '',
		pressed: false,
		loggedIn: false,
	}

	componentDidMount() {
		const { small } = this.state
		const sticky = document.getElementById('sticky')
		this.setState({
			innerWidth: window.innerWidth,
		})
		if (window.pageYOffset > 0) {
			this.setState({
				small: true,
			})
		}
		isAuthenticate() ? this.setState({ loggedIn: true }) : this.setState({ loggedIn: false });
		window.addEventListener('scroll', event => {
			let scroll = this.scrollY
			if (scrollY === 0 && !small) {
				this.setState({
					small: false,
				})
			} else if (scrollY > 0 && !small) {
				this.setState({
					small: true,
				})
			}
		})
	}

	pressMenuBtn() {
		this.setState({
			pressed: !this.state.pressed,
		})
	}

	logout() {
		Cookie.remove('app.access_token')
		Cookie.remove('app.refresh_token')
		Cookie.remove('app.Role', 'client')
		Cookie.remove('app.userName')
		Cookie.remove('app.expires_in')
		Cookie.remove('app.expires_at')
		Cookie.remove('app.userId')

		notification.success({
			message: 'Desconectado com sucesso!',
		})

		setTimeout(
			function () {
				window.location.href = '/login'
			}.bind(this),
			2500
		)
	}

	render() {
		const { inside } = this.props
		const { innerWidth, small } = this.state

		const menu = (
			<Menu selectable={false}>
				<Menu.Item>
					<div className="rfq__widget__system-status__item">
						<strong>Olá, {Cookie.get('app.userName')}</strong>
						<div>
							<strong>Função:</strong>{' '}
							<span style={{ textTransform: 'capitalize' }}>
								{Cookie.get('app.Role')}
							</span>
						</div>
						<div className="rfq__widget__system-status__item">
							<strong>Email:</strong> {Cookie.get('app.userName')}
						</div>
					</div>
				</Menu.Item>
				<Menu.Divider />
				<Menu.Item>
					<a href="/perfil/me/dados">
						<i className="topbar__dropdownMenuIcon icmn-user" /> Editar perfil
					</a>
				</Menu.Item>
				<Menu.Item>
					<a href="/perfil/me/agenda">
						<i className="topbar__dropdownMenuIcon icmn-user" /> Meus compromissos
					</a>
				</Menu.Item>
				<Menu.Divider />
				<Menu.Item>
					<a onClick={this.logout}>
						<i className="topbar__dropdownMenuIcon icmn-exit" /> Sair
					</a>
				</Menu.Item>
			</Menu>
		)

		return (
			<Container id="sticky" inside={inside} className={small && 'small'}>
				<div className={`container ${this.state.pressed && "collapse"}`}>
					<Link href="/">
						<a>
							<img
								src={
									small || inside || innerWidth < 980
										? '/static/logo.svg'
										: '/static/logo_cinza.svg'
								}
								id="logo-header"
								alt="Logotipo SigoClínica"
							/>
						</a>
					</Link>
					{
						this.state.loggedIn
							?
							<>
								<Dropdown
									overlay={menu}
									trigger={['click']}
									placement="bottomRight"
									onVisibleChange={this.addCount}
									size={10}
									className="account-dropdown"
								>
									<a className="ant-dropdown-link" href="/">
										<Avatar
											className="topbar__avatar icon-position-12"
											shape="square"
											size={38}
											icon="user"
										/>
									</a>
								</Dropdown>
							</>
							:
							<MenuOutlined
								className="hamburguerBtn"
								onClick={this.pressMenuBtn.bind(this)}
								style={{
									fontSize: "25px",
									color: this.state.pressed ? "rgb(40, 210, 150)" : "#76beac",
									backgroundColor: this.state.pressed ? "rgb(146, 146, 146, .2)" : "white",
									padding: "10px",
									borderRadius: "50%",
									transition: ".5s"
								}}
							/>
					}

					{isAuthenticate() ? (
						<></>
					) : (
						<div className={`headerNavBar`}>
							<div className="socialMediaContainer d-inline-block">
								<a
									href="https://blogsigoclinicas.com.br/"
									target="_blank"
									className="link"
								>
									<div className="buttonContainer">
										<p>Blog</p>
									</div>
								</a>
							</div>
							<Link href="/landingpage">
								<span className="button">Cadastrar Clínica</span>
							</Link>
							<Link href="/login">
								<a className="signNav link">Entrar / Registrar</a>
							</Link>
						</div>
					)}

				</div>
			</Container>
		)
	}
}

export default Sticky

