    }

    .headerNavBar {
      width:80%;
      display: flex;
      flex-direction: column;
    }

    .socialMediaContainer, .signNav{
      margin-top: 20px!important;
      margin-bottom: 20px!important;
      display: block!important;
    }

    .buttonContainer {
      color: rgb(118, 190, 172);
    }

    .socialMediaContainer .buttonContainer {
      margin-right: 0!important;
      width:auto!important;
      max-width:auto!important;
    }

    .button {
      border: none!important;
      background-color: transparent!important;
      color: rgb(118, 190, 172)!important;
      cursor: pointer!important;
      font-size: 16px!important;
      font-family: 'Source Sans Pro', sans-serif!important;
      font-weight: 800!important;
      text-transform: uppercase!important;
      text-decoration: none!important;
      margin-right:0!important;
    }

    .link {
      color: rgb(118, 190, 172)!important;
    }

    .hamburguerBtn {
      display:block;
    }

    &.small {
      padding: 20px 0;
      background: #ffffff;
      box-shadow: 0px -12px 20px 0px black;

      .container {
        div {
          .link {
            color: #000000;
          }
        }
      }
      }
    }

    .account-dropdown {
      right: 50px;
    }
  }
  }
`;

import React, { Fragment } from "react";
import Sticky from "../Sticky";
import Footer from "../Footer";
import { Hero } from "./styles";
import TermsContent from "./TermsContent";

class TermsComponent extends React.Component {
  componentDidMount() {}

  render() {
    return (
      <Fragment>
        <Sticky inside={true} />
        <Hero>
          <div className="container">
             <TermsContent />
          </div>
        </Hero>
        <Footer />
      </Fragment>
    );
  }
}

export default TermsComponent;

import styled from "styled-components";

export const Hero = styled.header`
  display: flex;
  align-items: center;
  justify-content: center;
  height: auto;
  margin: 170px 0 60px;
  position: relative;
  overflow: hidden;

  .title {
    text-align: center;

  }

  .description {
    text-align: justify;
  }

  form {
    min-width: 400px;
    width: auto;
    padding: 20px;
    border: 1px solid #00000020;
    box-shadow: 0 2px 2px #00000020;
    border-radius: 2px;

    .ant-form-item {
      margin-bottom: 5px;
      padding-bottom: 8px;
    }

    .mb-2 {
      text-align: center;

      .utils__link {
        color: #74708d;
        -webkit-transition: all 0.3s cubic-bezier(0.645, 0.045, 0.355, 1);
        transition: all 0.3s cubic-bezier(0.645, 0.045, 0.355, 1);

        :hover {
          color: #00ba9e;
          -webkit-transition: all 0.3s cubic-bezier(0.645, 0.045, 0.355, 1);
          transition: all 0.3s cubic-bezier(0.645, 0.045, 0.355, 1);
        }
      }

      .span {
        color: #bdb9d6;
      }
    }

    .form-actions {
      padding-top: 1.53rem;
      margin: 1.53rem 0 0.5rem;

      .btn-green {
        height: 35px;
        width: 100%;
        border: 1px solid #00ba9e;
        border-radius: 5px;
        color: #fff;
        background: #00ba9e;

        :hover {
          border: 1px solid #00ba9e;
          background: #fff;
          color: #00ba9e;
        }
      }
    }
    @media (max-width: 425px) {
      width: 100%;
      box-shadow: none;
      border: none;
      min-width: auto;
    }
  }
`;

module.exports = {
  target: "serverless",
  useFileSystemPublicRoutes: false,
  poweredByHeader: false,
  mode: process.env.NODE_ENV,
};

