.header .nav li{
    text-transform: uppercase;
    font-size: 17px;
    margin: 0 15px;
    font-weight: 400;
}

.header .nav li:first-child {
    display: none;
}

.header .nav li a{
    text-decoration: none;
    color: #333;
}
.header .nav li.gratis{
    background-color:#3ebfab;
    margin-top: -5px;
    padding: 5px 7px;
    border-radius:3px;
}
.header .nav li.gratis a{
    color: #fff !important;
}
.header .nav li i{
    font-size: 25px;
    margin-right: 8px;
}
.header .nav li:hover{
    cursor: pointer;
}

/* Main */
.banner{
    width: 100%;
    background-color: #ccc;
    background-image: url(/static/landingpage/banner-header.png);
    background-repeat: no-repeat;
    background-size: cover;
    padding: 30px 0;
    height: auto;
    float: left;
}
.banner .left{
    width: 50%;
    float: left;
}
.banner .right{
    width: 50%;
    height:auto;
    float: right;
}
.banner .right .text{
    background-color: #3ebfaba8;
    color: #fff;
    padding: 30px 35px 20px 35px;
    font-size: 2.5em;
    text-transform: uppercase;
    font-weight: 200;
    line-height: 55px;
    font-family: 'Open Sans', sans-serif !important;
}
.banner .right .text-link{
    background-color: #e4413ee0;
    color: #fff;
    padding: 10px 35px;
    font-size: 2.5em;
    text-transform: uppercase;
    font-weight:bold;
    font-family: 'Open Sans', sans-serif !important;
}
.banner .inputs{
    display: flex;
    flex-wrap: wrap;
    width: 100%;
    justify-content: space-around;
}
.banner .inputs .input-local{
    background-color: #fff;
    background-image: url(/static/landingpage/iconlocal.png);
    background-repeat: no-repeat;
    background-size: 45px;
    background-position: left;
    font-family: 'Open Sans', sans-serif !important;
    height:45px;
    padding: 5px 55px;
    font-size: 16px;
    border-radius:10px;
    width:35%;
    outline: none;
    border: none;
    margin: 20px 0;
}
.banner .inputs .input-email{
    background-color: #fff;
    background-image: url(/static/landingpage/iconsearch.png);
    background-repeat: no-repeat;
    background-size: contain;
    font-family: 'Open Sans', sans-serif !important;
    height: 45px;
    font-size: 16px;
    padding: 5px 55px;
    border-radius: 10px;
    width: 35%;
    outline: none;
    border: none;
    margin: 20px 0;
}

.block2{
    background-color: #fff;
    padding: 50px 0 50px 0;
    text-align: center;
}
.block2 h2{
    color:#ea403f;
    font-size: 45px;
    font-weight: 400;
    text-transform: uppercase;
}
.block2 p{
    color: #333;
    font-size: 1.4em;
    line-height: 30px;
}

.features{
    background-color:#d9edee;
    padding: 30px 0;
}
.features .left{
    display: flex;
    width: 50%;
}
.features .left img{
    max-width: 100%;
    height: auto;
}
.features .right{
    display: flex;
    align-items: center;
    justify-content: center;
    flex-direction: column;
    width: 50%;
}
.features .right .plus{
    padding: 20px 0;
    height: 100px;
    display: flex;
    align-items: center;
    width: 80%;
}
.features .right .plus i{
    color: #99979a;
    font-size: 6em;
    margin-right: 25px;
}
.features .right .plus span{
    color: #99979a;
    font-size: 2em;
    line-height: 30px;
    font-weight: 300;
}

.features-two{
    background-color:#fff;
    padding: 30px 0;
}
.features-two .left{
    display: flex;
    flex-direction: column;
    flex-wrap: nowrap;
    width: 50%;
}
.features-two .left img{
    max-width: 100%;
    height: auto;
}
.features-two .left .icons{
    display: flex;
    flex-direction: column;
    margin-top: 55px;
}
.features-two .left .img-phone{
    display: flex;
    flex-direction: column;
    margin-top:-20px;
}
.features-two .right{
    display: flex;
    flex-direction: column;
    width: 50%;
}
.features-two .right .circle-title{
    display: flex;
    background: #3ebfab;
    width: 35%;
    margin-left: 20%;
    border-radius: 50%;
    padding: 80px 20px;
    z-index: 1;
}
.features-two .right .circle-title span{
    color: #fff;
    text-transform: uppercase;
    font-weight: 600;
    font-size: 30px;
    margin-left: 30px;
}
.features-two .right .circle-title .fa-plus{
    color: #99979a;
    font-size: 12em;
    margin-top: -80px;
    margin-left: -25px;
}
.features-two .right ul.list{
    background-color: #a4a5aa;
    padding: 15px 20px;
    margin-left: 10%;
    margin-top: -15px;
    list-style: none;
}
.features-two .right ul.list li::before{
    content:'\\2022';
    margin-right: 5px;
    color:#666;
}
.features-two .right ul.list li{
    color: #fff;
    padding: 10px 0;
    font-size: 1.5em;
    font-weight: 500;
}

.experiment{
    background-color: #ccc;
    background-image: url(/static/landingpage/banner-rodape.png);
    background-repeat: no-repeat;
    background-size: cover;
    padding: 30px 0;
    height: auto;
    display: flex;
    align-content: flex-end;
    justify-content: end;
}
.experiment .left{
    width: 50%;
    height:auto;
    align-self: flex-end;
    padding-left: 25px;
}
.experiment .left .text{
    background-color: #3ebfaba8;
    color: #fff;
    padding: 30px 35px 20px 35px;
    font-size: 3.5em;
    text-transform: uppercase;
    font-weight: 200;
    line-height: 65px;
    font-family: 'Open Sans', sans-serif !important;
}
.experiment .left .text-link{
    background-color: #e4413ee0;
    color: #fff;
    padding: 10px 35px;
    font-size: 2.7em;
    text-transform: uppercase;
    font-weight:bold;
    font-family: 'Open Sans', sans-serif !important;
}
.text-link a{
    color: #fff;
}
.experiment .left .input{
    background-color: #fff;
    height:45px;
    padding: 5px 10px;
    font-size: 18px;
    border-radius:10px;
    text-align: center;
    width:50%;
    outline: none;
    border: none;
    margin: 20px 0;
}

.contatos{
    display: flex;
    align-items: center;
    text-align: center;
    padding: 50px 0 50px 0;
}
.contatos h2{
    color:#ea403f;
    font-size: 45px;
    font-weight: 400;
    text-transform: uppercase;
}
.contatos .icons{
    display: flex;
    align-items: center;
    justify-content: space-around;
}
.contatos .icons a{
    text-decoration: none;
    color: #99979a;
}
.contatos .icons a i{
    font-size: 6em;
}

.contact-Form {
  padding: 0px 250px;


  .ant-form-item {
    margin-bottom: 15px;
  }


  button[type="submit"] {
    background-color: #3ebfab !important;
    border-color: #3ebfab;
    float: right;
  }

}

/* Extras */
a, button, select, input, textarea{
    outline: none;
    text-decoration: none;
}
.display-none{
    display: none;
}
.container{
    width: 70%;
    max-width: 70%;
    height: auto;
    margin: 0 auto;
}
.flex{
    display: flex;
}
.space-between{
    justify-content: space-between;
}
.clearfix{
    clear: both;
}

