export const Types = {
  CLIENTE_DETAILS: "cliente/CLIENTE_DETAILS",
  CLIENTE_DETAILS_SUCCESS: "cliente/CLIENTE_DETAILS_SUCCESS",
  CLIENTE_DETAILS_FAILURE: "cliente/CLIENTE_DETAILS_FAILURE"
};

const INITIAL_STATE = {
  data: [],
  loading: false,
  error: false
};

export default function cliente(state = INITIAL_STATE, action) {

  switch (action.type) {

    case Types.CLIENTE_DETAILS:
      return{
        ...state,
        loading: true
      };

    case Types.CLIENTE_DETAILS_SUCCESS:
      return{
        ...state,
        data: action.payload.data,
        loading: false,
        error: false
      };

    case Types.CLIENTE_DETAILS_FAILURE:
      return{
          ...state,
          data: [],
          loading: false,
          error: true
      };

    default:
      return state;
  }
}

export const Creators = {
  clienteDetails: id => ({
    type: Types.CLIENTE_DETAILS,
    payload: { id }
  }),
  clienteDetailsSuccess: data => ({
    type: Types.CLIENTE_DETAILS_SUCCESS,
    payload: { data }
  }),
  clienteDetailsFailure: data => ({
      type: Types.CLIENTE_DETAILS_FAILURE,
      payload: { data }
  })
};

export const Types = {
  CLINICAS_LIST: "clinicas/CLINICAS_LIST",
  CLINICAS_LIST_SUCCESS: "clinicas/CLINICAS_LIST_SUCCESS",
  CLINICA_DETAILS: "clinicas/CLINICA_DETAILS",
  CLINICA_DETAILS_SUCCESS: "clinicas/CLINICA_DETAILS_SUCCESS"
};

const INITIAL_STATE = {
  data: [],
  loading: false
};

export default function clinicas(state = INITIAL_STATE, action) {

  switch (action.type) {

    case Types.CLINICAS_LIST:
      return {
        ...state,
        loading: true
      };

    case Types.CLINICAS_LIST_SUCCESS:
      return {
        ...state,
        data: action.payload.data,
        loading: false
      };

    case Types.CLINICA_DETAILS:
      return{
        ...state,
        loading: true
      };

    case Types.CLINICA_DETAILS_SUCCESS:
      return{
        ...state,
        data: action.payload.data,
        loading: false
      };

    default:
      return state;
  }
}

export const Creators = {
  clinicasList: () => ({
    type: Types.CLINICAS_LIST
  }),
  clinicasListSuccess: data => ({
    type: Types.CLINICAS_LIST_SUCCESS,
    payload: { data }
  }),
  clinicaDetails: id => ({
    type: Types.CLINICA_DETAILS,
    payload: { id }
  }),
  clinicaDetailsSuccess: data => ({
    type: Types.CLINICA_DETAILS_SUCCESS,
    payload: { data }
  })
};

import { combineReducers } from "redux";

import clinicas from "./clinicas";
import cliente from "./cliente";
import profissionais from "./profissionais";

export default combineReducers({
    clinicas,
    cliente,
    profissionais
});

export const Types = {
  PROFISSIONAIS_LIST: "profissionais/PROFISSIONAIS_LIST",
  PROFISSIONAIS_LIST_SUCCESS: "profissionais/PROFISSIONAIS_LIST_SUCCESS"
};

const INITIAL_STATE = {
  data: [],
  loading: false
};

export default function profissionais(state = INITIAL_STATE, action) {

  switch (action.type) {

    case Types.PROFISSIONAIS_LIST:
      return {
        ...state,
        loading: true
      };

    case Types.PROFISSIONAIS_LIST_SUCCESS:
      return {
        ...state,
        data: action.payload.data,
        loading: false
      };

    default:
      return state;
  }
}

export const Creators = {
  profissionaisList: idClinica => ({
    type: Types.PROFISSIONAIS_LIST,
    idClinica
  }),
  profissionaisListSuccess: data => ({
    type: Types.PROFISSIONAIS_LIST_SUCCESS,
    payload: { data }
  })
};

import { createStore, applyMiddleware } from "redux";
import createSagaMiddleware from "redux-saga";

import rootReducer from "./ducks";
import rootSaga from "./sagas";

const sagaMiddleware = createSagaMiddleware();

const middlewares = [sagaMiddleware];

middlewares.push(sagaMiddleware);

const store = createStore(rootReducer, applyMiddleware(...middlewares));

sagaMiddleware.run(rootSaga);

export default store;

import { call, put } from "redux-saga/effects";
import api from '../../services/api';
import Cookie from "js-cookie"
import { Creators as ClienteActions } from "../ducks/cliente";

function getClienteAPI(id) {
    var config = {
        headers: {'Authorization': `Bearer ${Cookie.get('app.access_token')}`}
    };

    return api.get(`/clientes/${id}`, config)
        .then(response => response.data)
        .catch(err => {
            throw err;
        });
}

export function* clienteDetails(action) {
    try {

        const data = yield call(getClienteAPI,action.payload.id);
        console.log('redux')
        console.log(data)

        yield put(ClienteActions.clienteDetailsSuccess(data));
  } catch (err) {
        yield put(ClienteActions.clienteDetailsFailure([],err));
        console.log(err);
  }
}

import { call, put } from "redux-saga/effects";
import api from "../../services/api";

import { Creators as ClinicasActions } from "../ducks/clinicas";

export function* clinicasList() {
  try {
    const { data } = yield call(
      api.get,
      `/clinicas?query[clean]&query[clinicas.ativo]=1`
    );
    yield put(ClinicasActions.clinicasListSuccess(data));
  } catch (err) {
    console.log(err);
  }
}

export function* clinicaDetails(action) {
  try {
    const { data } = yield call(api.get, `/clinicas/${action.payload.id}`);
    yield put(ClinicasActions.clinicaDetailsSuccess(data));
  } catch (err) {
    console.log(err);
  }
}

import { all, takeLatest } from "redux-saga/effects";

import { Types as ClinicasTypes } from "../ducks/clinicas";
import { clinicasList, clinicaDetails } from "./clinicas";

import { Types as ClienteTypes } from "../ducks/cliente";
import { clienteDetails } from "./cliente";

import { Types as ProfissionaisTypes } from "../ducks/profissionais";
import { profissionaisList } from "./profissionais";

export default function* rootSaga() {
  return yield all([
      takeLatest(ClinicasTypes.CLINICAS_LIST, clinicasList),
      takeLatest(ClinicasTypes.CLINICA_DETAILS, clinicaDetails),
      takeLatest(ClienteTypes.CLIENTE_DETAILS, clienteDetails),
      takeLatest(ProfissionaisTypes.PROFISSIONAIS_LIST, profissionaisList)
  ]);
}

import { call, put } from "redux-saga/effects";
import api from "../../services/api";

import { Creators as ProfissionaisActions } from "../ducks/profissionais";

export function* profissionaisList(action) {
  try {
    const { data } = yield call(api.get, `/clinicas/${action.idClinica}/profissionais`);
    yield put(ProfissionaisActions.profissionaisListSuccess(data));
  } catch (err) {
    console.log(err);
  }
}

